-- Schema for Domain: sample | Business: Genomics Biotech | Version: v1_mvm
-- Generated on: 2026-05-06 15:33:29

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `genomics_biotech_ecm`.`sample` COMMENT 'Authoritative SSOT for biological sample identity, chain-of-custody, and lifecycle tracking across accessioning, aliquoting, storage, and disposal. Manages sample metadata, IRB consent linkage, PHI de-identification flags, specimen types, collection metadata, and LIMS-driven workflow assignments in LabVantage. Underpins traceability for clinical, research, and QC specimens.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`sample_specimen` (
    `sample_specimen_id` BIGINT COMMENT 'Unique surrogate identifier for the biological specimen record in the Genomics Biotech data lakehouse. Primary key for all chain-of-custody and traceability references. Role: MASTER_RESOURCE.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Specimens originate from customer accounts (research institutions, hospitals, biotech companies). Essential for billing, consent compliance, regulatory reporting, and data use agreement enforcement. C',
    `batch_id` BIGINT COMMENT 'Foreign key linking to supply.batch. Business justification: Specimen processing uses supply materials from specific batches (processing reagents, stabilizers). GMP traceability requires linking specimens to the supply batch of processing material used, enablin',
    `change_control_id` BIGINT COMMENT 'Foreign key linking to quality.change_control. Business justification: Change controls may affect specimens (e.g., storage location changes, new handling procedures). Labs link change controls to affected specimens for traceability and regulatory compliance.',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Specimens are collected using specific collection kit products. LIMS systems track kit SKU for regulatory compliance (21 CFR Part 11), lot traceability, and QC correlation. Essential for genomics oper',
    `deviation_id` BIGINT COMMENT 'Foreign key linking to quality.quality_deviation. Business justification: Specimens trigger quality deviations (failed QC, contamination, handling errors). Labs link specimens to deviations for root cause analysis, CAPA, and regulatory compliance. Essential for GxP traceabi',
    `header_id` BIGINT COMMENT 'Foreign key linking to order.order_header. Business justification: Specimens are collected and processed to fulfill customer sequencing/testing service orders. Essential for tracking which specimens support which commercial transactions, TAT compliance, and revenue r',
    `material_id` BIGINT COMMENT 'Foreign key linking to supply.material. Business justification: Specimens are processed using specific materials (extraction kits, culture media, reagents). Real-world LIMS systems track material lot numbers for regulatory traceability, recall management, and CoA ',
    `parent_specimen_sample_specimen_id` BIGINT COMMENT 'Self-referencing identifier pointing to the parent specimen from which this specimen was derived (e.g., an aliquot derived from a primary blood draw, or an extracted DNA specimen derived from a tissue biopsy). Enables hierarchical specimen lineage and chain-of-custody traceability.',
    `lot_id` BIGINT COMMENT 'Foreign key linking to reagent.lot. Business justification: Specimens are processed using specific reagent lots for nucleic acid extraction, library preparation, and quality control. Critical for batch effect analysis, regulatory traceability (21 CFR Part 11),',
    `production_batch_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_batch. Business justification: GMP batch traceability: QA must identify which production batch processed a specimen for batch disposition, recall, and deviation investigation. In genomics biotech, specimens are processed in discret',
    `research_protocol_id` BIGINT COMMENT 'Reference to the Institutional Review Board (IRB) protocol under which this specimen was collected and is authorized for use. Mandatory for all human-derived specimens used in research. Ensures regulatory traceability to the governing ethics approval.',
    `subject_id` BIGINT COMMENT 'Reference to the biological subject (human patient, research participant, animal, or environmental source) from whom the specimen was collected. Links to the subject master record for IRB consent and PHI management. Classified as restricted due to potential re-identification risk.',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: Clinical specimens used in 510k or CE-IVD submissions require traceability to regulatory dossiers for FDA/notified body audits and validation evidence packages. Essential for IVD product regulatory co',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to supply.supplier. Business justification: When specimens are received from external biobanks, CROs, or collaborating institutions, tracking the supplier is critical for specimen provenance, quality management, audit trails, and vendor perform',
    `validation_study_id` BIGINT COMMENT 'Foreign key linking to quality.validation_study. Business justification: Validation studies use real specimens as test samples to demonstrate assay performance. Labs track which specimens were used in each validation for regulatory submissions and audit trails.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to manufacturing.work_order. Business justification: Specimens are processed through manufacturing work orders for library preparation, sequencing runs, and array-based assays. This link enables tracking specimen-to-manufacturing traceability required f',
    `a260_a280_ratio` DECIMAL(18,2) COMMENT 'Ratio of absorbance at 260 nm to 280 nm as measured by NanoDrop spectrophotometer, indicating nucleic acid purity. Acceptable range is 1.8–2.0 for DNA and ~2.0 for RNA. Values outside this range indicate protein or solvent contamination.',
    `aliquot_number` STRING COMMENT 'Sequential number identifying this specimen as a specific aliquot derived from a parent specimen (e.g., aliquot 3 of 8 from a primary blood draw). Used for inventory management, depletion tracking, and ensuring equitable distribution of limited specimens across assays.',
    `collection_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the country in which the specimen was collected (e.g., USA, GBR, DEU). Required for GDPR cross-border data transfer compliance, biospecimen import/export regulatory tracking, and population genomics stratification.. Valid values are `^[A-Z]{3}$`',
    `collection_method` STRING COMMENT 'Standardized method used to collect the specimen from the subject. Influences pre-analytical variability, QC acceptance criteria, and downstream genomic assay performance. [ENUM-REF-CANDIDATE: venipuncture|finger_prick|biopsy|swab|saliva_collection|urine_void|bone_marrow_aspirate|surgical_resection|liquid_biopsy|environmental_swab|other — promote to reference product]',
    `collection_site_code` STRING COMMENT 'Coded identifier for the anatomical site or environmental location from which the specimen was collected (e.g., left_arm_antecubital, liver_biopsy_segment_VI, tumor_margin). Aligns with SNOMED CT body site codes. Critical for oncology and multi-site clinical studies.',
    `collection_timestamp` TIMESTAMP COMMENT 'Date and time at which the specimen was physically collected from the subject, recorded in ISO 8601 format with timezone offset. Critical for pre-analytical stability calculations, TAT (Turnaround Time) tracking, and time-sensitive assay validity windows (e.g., cfDNA stability). Serves as the MEASUREMENT_OR_VALUE temporal anchor for this resource.',
    `concentration_ng_ul` DECIMAL(18,2) COMMENT 'Concentration of extracted nucleic acid (DNA or RNA) in nanograms per microliter (ng/µL), measured post-extraction by fluorometric or spectrophotometric methods (e.g., Qubit, NanoDrop). Used for library preparation input normalization and QC pass/fail determination.',
    `consent_status` STRING COMMENT 'Current status of the subjects informed consent for use of this specimen in research or clinical testing. Governs permissible downstream uses of the specimen and derived genomic data. Mandatory for all human-derived specimens under IRB, HIPAA, and GDPR requirements.. Valid values are `consented|withdrawn|pending|not_required|expired`',
    `container_type` STRING COMMENT 'Type of physical container or tube in which the specimen is stored (e.g., EDTA tube, SST tube, PAXgene tube, cryovial, FFPE block). Affects pre-analytical processing requirements and downstream assay compatibility. [ENUM-REF-CANDIDATE: EDTA_tube|SST_tube|PAXgene_tube|cryovial|FFPE_block|microcentrifuge_tube|96_well_plate|other — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time at which the specimen record was first created in LabVantage LIMS and ingested into the Genomics Biotech data lakehouse. Serves as the RECORD_AUDIT_CREATED category for this MASTER_RESOURCE entity. Used for data lineage, audit trail, and SLA tracking.',
    `disposal_timestamp` TIMESTAMP COMMENT 'Date and time at which the specimen was permanently disposed of or destroyed, recorded in LabVantage LIMS. Populated only when lifecycle_status is disposed. Required for biorepository inventory reconciliation, regulatory audit trails, and biohazardous waste compliance documentation.',
    `dna_integrity_number` DECIMAL(18,2) COMMENT 'DNA Integrity Number (DIN) score on a scale of 1-10 as measured by TapeStation, indicating genomic DNA quality and fragmentation level. Used for WGS and WES library preparation QC gating. Null for non-DNA specimens.',
    `external_specimen_code` STRING COMMENT 'Specimen identifier assigned by the submitting institution, clinic, or partner laboratory prior to receipt at Genomics Biotech. Used for cross-referencing with external Laboratory Information Systems (LIS) and Electronic Medical Records (EMR). May differ from the internal LIMS accession number.',
    `freeze_thaw_count` STRING COMMENT 'Number of freeze-thaw cycles the specimen has undergone since collection. Excessive freeze-thaw cycles degrade nucleic acid integrity and protein stability, impacting assay performance. Tracked in LabVantage LIMS for QC and specimen integrity assessment.',
    `hazard_classification` STRING COMMENT 'Biosafety Level (BSL) classification of the specimen per CDC/NIH biosafety guidelines, indicating the containment requirements for safe handling, processing, and disposal. Drives PPE requirements, laboratory access controls, and waste disposal procedures.. Valid values are `BSL1|BSL2|BSL3|non_hazardous|unknown`',
    `label` STRING COMMENT 'Human-readable label printed on the specimen container or tube, typically matching the LIMS accession number or a barcode-encoded identifier. Used for physical identification during laboratory handling, storage, and retrieval. Serves as the IDENTITY_LABEL category for this MASTER_RESOURCE entity.',
    `lifecycle_status` STRING COMMENT 'Current state of the specimen within the Genomics Biotech laboratory workflow lifecycle. Drives LIMS workflow routing, storage management, and chain-of-custody audit events. Serves as the LIFECYCLE_STATUS category for this MASTER_RESOURCE entity. [ENUM-REF-CANDIDATE: accessioned|in_processing|extracted|archived|depleted|disposed|rejected|on_hold — promote to reference product]',
    `lims_accession_number` STRING COMMENT 'Externally-known unique accession number assigned by LabVantage LIMS at the point of specimen receipt. This is the primary business identifier used across laboratory workflows, requisition forms, and chain-of-custody documentation. Serves as the BUSINESS_IDENTIFIER category for this MASTER_RESOURCE entity.. Valid values are `^[A-Z]{2,4}-[0-9]{8,12}$`',
    `mass_mg` DECIMAL(18,2) COMMENT 'Mass of the specimen in milligrams (mg) at the time of accessioning or most recent measurement. Applicable to solid specimens (tissue biopsies, FFPE blocks, dried blood spots). Null for liquid specimens where volume_ul is used instead.',
    `matrix_type` STRING COMMENT 'Physical matrix or medium in which the specimen is preserved or suspended (e.g., aqueous buffer, FFPE paraffin block, dried blood spot, frozen tissue). Determines storage temperature requirements, extraction chemistry, and analytical method compatibility. [ENUM-REF-CANDIDATE: aqueous|solid|semi-solid|dried|fixed|frozen|other — 7 candidates stripped; promote to reference product]',
    `nucleic_acid_type` STRING COMMENT 'Type of nucleic acid present in or extracted from the specimen. Determines compatible sequencing library preparation protocols (e.g., WGS, WES, RNA-Seq, ctDNA panel). Null or not_applicable for unextracted specimens. [ENUM-REF-CANDIDATE: gDNA|cfDNA|RNA|total_RNA|mRNA|ctDNA|not_applicable — 7 candidates stripped; promote to reference product]',
    `passage_count` STRING COMMENT 'Number of times the specimen or derived cell line has been sub-cultured or passaged. Relevant for cell-based specimens and primary cultures. Higher passage counts may indicate genomic drift and affect assay validity.',
    `phi_deidentification_tier` STRING COMMENT 'Specifies the de-identification method applied to this specimen record per HIPAA standards: Safe Harbor (removal of 18 identifiers), Expert Determination (statistical certification), Pseudonymisation (GDPR Article 4(5)), or Identified (PHI present). Drives data access tier controls and downstream sharing permissions.. Valid values are `safe_harbor|expert_determination|pseudonymised|identified|not_applicable`',
    `phi_deidentified` BOOLEAN COMMENT 'Indicates whether Protected Health Information (PHI) has been removed or de-identified from this specimen record in accordance with HIPAA Safe Harbor or Expert Determination methods. When True, the record may be used in broader research contexts without individual consent restrictions.',
    `priority_level` STRING COMMENT 'Processing priority assigned to the specimen, governing TAT (Turnaround Time) SLA targets and workflow queue position in LabVantage LIMS. STAT specimens require immediate processing; routine specimens follow standard scheduling.. Valid values are `STAT|routine|urgent|research`',
    `received_timestamp` TIMESTAMP COMMENT 'Date and time at which the specimen was received and accessioned into the Genomics Biotech laboratory, recorded in LabVantage LIMS. Used to calculate transit time, pre-analytical cold-chain compliance, and TAT (Turnaround Time) SLA metrics.',
    `rejection_reason` STRING COMMENT 'Coded reason for specimen rejection at accessioning or QC review. Populated only when lifecycle_status is rejected. Used for pre-analytical quality monitoring, root cause analysis, and SOP improvement. [ENUM-REF-CANDIDATE: insufficient_volume|hemolyzed|lipemic|clotted|wrong_container|mislabeled|temperature_excursion|expired|contaminated|other — promote to reference product]',
    `rin_score` DECIMAL(18,2) COMMENT 'RNA Integrity Number (RIN) score on a scale of 1-10 as measured by Bioanalyzer or TapeStation, indicating RNA quality. A RIN score ≥7 is typically required for RNA-Seq library preparation. Null for non-RNA specimens.',
    `specimen_type` STRING COMMENT 'Classification of the biological material type collected from the subject. Drives downstream workflow routing, extraction protocols, and storage conditions in LabVantage LIMS. Serves as the CLASSIFICATION_OR_TYPE category for this MASTER_RESOURCE entity. [ENUM-REF-CANDIDATE: blood|tissue|saliva|urine|plasma|cfDNA|FFPE|bone_marrow|buccal_swab|stool|other — promote to reference product]',
    `storage_location_code` STRING COMMENT 'Coded identifier for the physical storage location of the specimen within the biorepository (e.g., freezer ID, rack, shelf, box, position). Enables physical retrieval, inventory management, and chain-of-custody tracking in LabVantage LIMS.',
    `storage_temperature_c` DECIMAL(18,2) COMMENT 'Required or actual storage temperature for the specimen in degrees Celsius (e.g., -80, -20, 4, 25). Used for cold-chain compliance monitoring, specimen integrity assessment, and deviation management.',
    `subtype` STRING COMMENT 'Further granular classification of the specimen within its primary type (e.g., for blood: whole_blood, PBMC, serum; for tissue: fresh_frozen, FFPE_block, FFPE_section; for cfDNA: cell_free_plasma). Enables precise protocol selection and QC thresholds in bioinformatics pipelines.',
    `tumor_content_pct` DECIMAL(18,2) COMMENT 'Estimated percentage of tumor cells (neoplastic cellularity) in the specimen as assessed by pathology review. Critical for somatic variant calling sensitivity, LOD (Limit of Detection) calculations, and clinical oncology reporting. Null for non-oncology specimens.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time at which the specimen record was most recently modified in LabVantage LIMS or the data lakehouse. Used for change data capture (CDC), audit trail compliance, and Silver layer incremental processing in Databricks.',
    `use_restriction_code` STRING COMMENT 'Coded data use restriction applicable to this specimen and its derived genomic data, aligned with GA4GH Data Use Ontology (DUO) codes (e.g., GRU: General Research Use, HMB: Health/Medical/Biomedical, DS: Disease-Specific). Governs permissible downstream research and data sharing activities.',
    `use_type` STRING COMMENT 'Intended use classification for the specimen: clinical diagnostic testing (IVD), research (RUO), internal QC (Quality Control), assay validation, proficiency testing (CAP/CLIA), or Research Use Only (RUO). Determines applicable regulatory framework, data handling requirements, and reporting obligations.. Valid values are `clinical|research|QC|validation|proficiency_testing|RUO`',
    `volume_ul` DECIMAL(18,2) COMMENT 'Volume of the specimen in microliters (µL) at the time of accessioning or most recent measurement. Used for aliquot planning, minimum volume QC checks, and assay feasibility assessment. Applicable to liquid specimens (blood, plasma, urine, saliva, cfDNA). Null for solid specimens where mass_mg is used instead.',
    CONSTRAINT pk_sample_specimen PRIMARY KEY(`sample_specimen_id`)
) COMMENT 'Core master entity representing a biological specimen collected from a subject (human, animal, or environmental source). Captures specimen identity, type classification (blood, tissue, saliva, FFPE, cfDNA, etc.), collection site, collection date/time, collection method, volume/mass, matrix type, PHI de-identification flag and tier, IRB protocol linkage, consent status, current lifecycle status (accessioned, in-processing, extracted, archived, depleted, disposed), and LIMS accession number from LabVantage. This is the SSOT for all biological material entering the genomics workflow and the anchor entity for chain-of-custody traceability.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`aliquot` (
    `aliquot_id` BIGINT COMMENT 'Unique surrogate identifier for the aliquot record in the Databricks Silver Layer. Primary key for the aliquot data product within the sample domain. Entity role: MASTER_RESOURCE — represents a physical sub-divided specimen unit managed as an independent trackable resource in LabVantage LIMS.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to supply.batch. Business justification: GMP traceability requires linking each aliquot to the specific supply batch of material used during aliquoting. Enables batch recall investigations and deviation root-cause analysis — a standard regul',
    `container_id` BIGINT COMMENT 'FK to sample.container',
    `experiment_id` BIGINT COMMENT 'Foreign key linking to research.experiment. Business justification: Aliquots are consumed in specific experiments (sequencing, CRISPR, assay validation). Linking aliquot to experiment is fundamental for reproducibility tracking, chain-of-custody, and experimental mate',
    `header_id` BIGINT COMMENT 'Foreign key linking to order.order_header. Business justification: Aliquots are prepared and consumed for specific customer service orders (sequencing runs, array processing). Required for inventory consumption tracking, billing reconciliation, and linking lab materi',
    `material_id` BIGINT COMMENT 'Foreign key linking to supply.material. Business justification: Aliquot preparation uses specific supply materials (buffers, consumables). GMP and LIMS traceability requires knowing which material was used per aliquot for quality investigations and regulatory audi',
    `parent_aliquot_id` BIGINT COMMENT 'Self-referencing identifier pointing to the immediate parent aliquot when this record represents a secondary or tertiary sub-division (aliquot-of-aliquot). Null for first-generation aliquots derived directly from the specimen. Enables multi-level aliquot hierarchy traversal.',
    `catalog_id` BIGINT COMMENT 'Foreign key linking to reagent.reagent_catalog. Business justification: Aliquots are prepared using specific reagent types (extraction kits, normalization buffers, stabilization reagents). Needed for protocol compliance verification, method validation studies, and ensurin',
    `lot_id` BIGINT COMMENT 'Foreign key linking to reagent.lot. Business justification: GMP/GLP aliquot preparation traceability: existing FK covers only the catalog entry, not the specific lot used. Lot-level traceability is required for reagent recall investigations and batch record co',
    `production_batch_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_batch. Business justification: Aliquots are the physical units consumed in manufacturing production batches (library construction, hybridization). Direct aliquot-to-batch traceability is required for GMP batch records, QC failure r',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Aliquots are created using specific reagent kits (extraction, library prep). Business need: protocol compliance verification, batch effect analysis in sequencing QC, reagent lot traceability for faile',
    `sample_consent_record_id` BIGINT COMMENT 'Reference to the Institutional Review Board (IRB) consent record governing the permissible uses of this aliquot. Ensures that downstream workflows (sequencing, research, clinical) are authorized under the applicable consent scope. Critical for HIPAA, GDPR, and NIH Genomic Data Sharing Policy compliance.',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the originating parent specimen from which this aliquot was derived. Supports parent-child lineage traceability back to the source biological specimen. Null if this aliquot is a top-level sub-division directly from the primary specimen.',
    `storage_location_id` BIGINT COMMENT 'Reference to the storage location record defining the physical storage unit (freezer, refrigerator, ambient rack) where this aliquot is currently housed. Supports chain-of-custody and cold-chain compliance tracking.',
    `study_id` BIGINT COMMENT 'Foreign key linking to research.study. Business justification: Aliquots are allocated to studies for biomarker analysis and translational genomics research. Study-level aliquot inventory tracking is a core biobank operation required for enrollment monitoring, sam',
    `validation_study_id` BIGINT COMMENT 'Foreign key linking to quality.validation_study. Business justification: Validation studies use aliquots as test samples for repeatability, reproducibility, and accuracy studies. Labs maintain traceability to aliquots used for regulatory compliance.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to manufacturing.work_order. Business justification: Aliquots are direct inputs to manufacturing processes (library prep, QC runs, sequencing). This link supports material consumption tracking, work order costing, batch genealogy, and regulatory traceab',
    `aliquot_type` STRING COMMENT 'Classification of the aliquot within the sub-division hierarchy. primary indicates first-generation aliquot from specimen; secondary and tertiary indicate downstream sub-divisions; pooled indicates a combined aliquot from multiple sources; reference indicates a reference material aliquot.. Valid values are `primary|secondary|tertiary|pooled|reference`',
    `aliquoting_timestamp` TIMESTAMP COMMENT 'Date and time at which this aliquot was physically created from the parent specimen or parent aliquot. Represents the principal real-world business event timestamp for this entity. Used for pre-analytical variable tracking, stability calculations, and chain-of-custody documentation.',
    `barcode` STRING COMMENT 'Unique barcode label affixed to the physical container holding this aliquot. Used for barcode-driven tracking, scanning at workstations, and chain-of-custody verification throughout laboratory workflows in LabVantage LIMS.',
    `collection_date` DATE COMMENT 'Date on which the original biological specimen was collected from the subject. Inherited from the parent specimen record. Critical for calculating specimen age, assessing pre-analytical variable impact, and meeting regulatory reporting timelines under CLIA and CAP.',
    `concentration` DECIMAL(18,2) COMMENT 'Measured concentration of the biological analyte (e.g., DNA, RNA, protein) in the aliquot. The unit of measure is captured in concentration_unit. Critical for library preparation normalization in Next-Generation Sequencing (NGS) workflows and Quality Control (QC) acceptance criteria.',
    `concentration_unit` STRING COMMENT 'Unit of measure for the concentration value recorded in the concentration field. Common units include ng/µL (nanograms per microliter) for DNA/RNA quantification, nM (nanomolar) for library quantification, and copies/µL for digital Polymerase Chain Reaction (PCR) applications.. Valid values are `ng/ul|ug/ml|mg/ml|nM|uM|copies/ul`',
    `container_status` STRING COMMENT 'Current operational status of the physical container holding the aliquot. in_use indicates container holds active aliquot material; empty indicates container has been emptied; discarded indicates container has been disposed of; pre_registered indicates container registered in LabVantage LIMS prior to receiving material (empty container inventory management).. Valid values are `in_use|empty|discarded|pre_registered`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this aliquot record was first created in the source LabVantage LIMS system and ingested into the Databricks Silver Layer. Supports audit trail requirements under GxP, CLIA, and SOX financial reporting for laboratory operations.',
    `disposal_date` DATE COMMENT 'Date on which the aliquot was physically disposed of or destroyed per retention policy, consent withdrawal, or regulatory requirement. Populated when lifecycle_status transitions to disposed or destroyed. Required for audit trail completeness under GxP and HIPAA.',
    `disposal_reason` STRING COMMENT 'Reason code for the disposal or destruction of the aliquot. Supports regulatory audit trails and consent management reporting. consent_withdrawn is critical for GDPR Article 17 right-to-erasure and HIPAA consent revocation workflows.. Valid values are `expired|consent_withdrawn|qc_failure|volume_depleted|protocol_end|contamination`',
    `dna_integrity_number` DECIMAL(18,2) COMMENT 'DNA Integrity Number (DIN) score measured by TapeStation, ranging from 1 (fully degraded) to 10 (fully intact). Applicable to genomic DNA aliquots. Used to assess suitability for Whole Genome Sequencing (WGS) and Whole Exome Sequencing (WES) library preparation. Null for non-DNA aliquots.',
    `expiry_date` DATE COMMENT 'Date after which the aliquot is considered expired and should not be used in clinical or research workflows. Calculated based on specimen type, storage conditions, and validated stability data per Standard Operating Procedure (SOP). Triggers automated alerts in LabVantage LIMS for disposal or review.',
    `freeze_thaw_count` STRING COMMENT 'Number of freeze-thaw cycles the aliquot has undergone since creation. Excessive freeze-thaw cycles degrade nucleic acid integrity and protein activity. Used to enforce maximum freeze-thaw limits per Standard Operating Procedure (SOP) and to flag aliquots that may be unsuitable for sensitive assays.',
    `hierarchy_level` STRING COMMENT 'Numeric depth of this aliquot within the parent-child hierarchy. Level 1 indicates a direct sub-division of the primary specimen; level 2 indicates an aliquot-of-aliquot; and so on. Enables efficient hierarchy traversal queries and enforces maximum sub-division depth policies.',
    `initial_volume_ul` DECIMAL(18,2) COMMENT 'Original volume of biological material dispensed into the aliquot container at the time of aliquoting, expressed in microliters (µL). Provides the baseline for volume consumption tracking and yield calculations.',
    `is_phi_deidentified` BOOLEAN COMMENT 'Indicates whether Protected Health Information (PHI) associated with this aliquot has been de-identified in accordance with HIPAA Safe Harbor or Expert Determination methods. True indicates de-identified; False indicates PHI is present and access controls apply. Governs data sharing eligibility for research and external collaborations.',
    `label` STRING COMMENT 'Human-readable label or name assigned to the aliquot for identification in laboratory workflows, reports, and LIMS displays. May include specimen accession number, aliquot sequence suffix, or study-specific naming conventions.',
    `lifecycle_status` STRING COMMENT 'Current state of the aliquot in its operational lifecycle. available indicates ready for use; consumed indicates fully used in a workflow; depleted indicates volume exhausted; reserved indicates allocated to a pending workflow; quarantined indicates held pending Quality Control (QC) review; disposed indicates removed per retention policy; destroyed indicates intentionally destroyed per protocol. [ENUM-REF-CANDIDATE: available|consumed|depleted|reserved|quarantined|disposed|destroyed — 7 candidates stripped; promote to reference product]',
    `lims_aliquot_code` STRING COMMENT 'The native aliquot identifier assigned by LabVantage LIMS at the time of accessioning or aliquoting. Used as the operational cross-reference key between the lakehouse Silver Layer and the LIMS source system.',
    `purity_ratio_260_230` DECIMAL(18,2) COMMENT 'Absorbance ratio at 260nm to 230nm measured by spectrophotometry. Indicates contamination by chaotropic salts, EDTA, or carbohydrates. Acceptable range is typically 2.0–2.2. Complements the A260/A280 ratio for comprehensive nucleic acid Quality Control (QC) assessment.',
    `purity_ratio_260_280` DECIMAL(18,2) COMMENT 'Absorbance ratio at 260nm to 280nm measured by spectrophotometry (e.g., NanoDrop). Indicates nucleic acid purity; acceptable DNA purity is typically 1.8–2.0 and RNA purity 2.0–2.2. Values outside range may indicate protein or solvent contamination affecting downstream Next-Generation Sequencing (NGS) performance.',
    `purpose` STRING COMMENT 'Intended downstream use of the aliquot. Drives workflow routing in LabVantage LIMS and determines which bioinformatics pipelines or Quality Control (QC) processes the aliquot will enter. Values include sequencing (Next-Generation Sequencing/NGS workflows), qc (Quality Control testing), archive (long-term storage), backup (redundancy), assay_validation (Clinical Assay Validation), and research (Research and Development).. Valid values are `sequencing|qc|archive|backup|assay_validation|research`',
    `qc_notes` STRING COMMENT 'Free-text notes recorded by laboratory personnel during Quality Control (QC) assessment. Documents observations, deviations, conditional pass justifications, or remediation actions taken. Supports audit trail requirements under Good Practice Regulations (GxP) and CLIA.',
    `qc_status` STRING COMMENT 'Result of the Quality Control (QC) assessment for this aliquot. pass indicates aliquot meets all acceptance criteria for its intended purpose; fail indicates one or more criteria not met; pending indicates QC not yet completed; conditional_pass indicates aliquot approved with documented exceptions; not_required indicates QC waived per Standard Operating Procedure (SOP).. Valid values are `pass|fail|pending|conditional_pass|not_required`',
    `rack_code` STRING COMMENT 'Identifier of the storage rack, plate, or box within the storage unit where this aliquot is positioned. Combined with well_position provides the precise physical location for robotic retrieval and manual locating in biobank operations.',
    `rin_score` DECIMAL(18,2) COMMENT 'RNA Integrity Number (RIN) score measured by Bioanalyzer or TapeStation, ranging from 1 (fully degraded) to 10 (fully intact). Applicable to RNA aliquots only. Minimum RIN thresholds are defined per assay type (e.g., RIN ≥ 7 for RNA-seq library preparation). Null for non-RNA aliquots.',
    `specimen_type` STRING COMMENT 'Biological specimen type of the aliquot material (e.g., whole blood, plasma, serum, saliva, tissue, FFPE, cell line, DNA extract, RNA extract, cfDNA). Inherited from the parent specimen and critical for downstream workflow routing and assay compatibility checks. [ENUM-REF-CANDIDATE: whole_blood|plasma|serum|saliva|tissue|ffpe|cell_line|dna_extract|rna_extract|cfdna|urine|csf|buffy_coat — promote to reference product]',
    `storage_temperature_c` DECIMAL(18,2) COMMENT 'Required storage temperature for this aliquot in degrees Celsius (°C). Common values include -80°C (ultra-low for long-term nucleic acid storage), -20°C (standard freezer), 4°C (refrigerated), and ambient (15–25°C). Drives cold-chain compliance monitoring and storage assignment.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this aliquot record in the source LabVantage LIMS system. Used for incremental data pipeline processing, change data capture, and audit trail completeness under GxP and ISO 15189.',
    `use_restriction_code` STRING COMMENT 'Standardized data use restriction code governing permissible downstream uses of this aliquot and its derived data. Codes follow GA4GH/dbGaP conventions: GRU (General Research Use), HMB (Health/Medical/Biomedical), DS (Disease-Specific), POA (Population Origins/Ancestry), NPU (Non-Profit Use Only), RUO (Research Use Only). Enforced during data access governance reviews.. Valid values are `GRU|HMB|DS|POA|NPU|RUO`',
    `volume_ul` DECIMAL(18,2) COMMENT 'Current measured volume of biological material in the aliquot container, expressed in microliters (µL). Decremented as material is consumed in workflows. Critical for determining aliquot sufficiency for downstream assays such as Next-Generation Sequencing (NGS) library preparation.',
    `volume_unit` STRING COMMENT 'Unit of measure for volume fields (volume_ul and initial_volume_ul). Standard unit is microliters (µL) for most genomics laboratory workflows; milliliters (mL) may be used for larger biobank specimens.. Valid values are `uL|mL|L`',
    `well_position` STRING COMMENT 'Alphanumeric position identifier within the storage rack, plate, or box (e.g., A01, B12, H08 for a 96-well plate layout). Used for precise physical localization of the aliquot within its storage container for robotic liquid handling and manual retrieval.. Valid values are `^[A-Z]{1,2}[0-9]{1,2}$`',
    CONSTRAINT pk_aliquot PRIMARY KEY(`aliquot_id`)
) COMMENT 'Represents a physical sub-division of a parent specimen created during aliquoting workflows, including the container holding it. Tracks aliquot volume, concentration, unit of measure, container identity (barcode, type, manufacturer, lot number, material, volume capacity), position in storage rack/plate/well, aliquot purpose (sequencing, QC, archive, backup), current lifecycle status, and container status (in-use, empty, discarded). Maintains parent-child lineage back to the originating specimen and supports multi-level aliquot hierarchies (aliquot-of-aliquot). Also serves as the master record for empty container inventory when pre-registered in LabVantage. Managed with barcode-driven tracking.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`accession` (
    `accession_id` BIGINT COMMENT 'Unique surrogate identifier for the accession record in the Databricks Silver Layer. Primary key for this entity. TRANSACTION_HEADER role — represents the formal intake event of a specimen into laboratory custody.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Accessions represent received samples from customer accounts. Required for order fulfillment tracking, billing reconciliation, customer-specific SLA enforcement, and regulatory classification routing.',
    `approval_id` BIGINT COMMENT 'Foreign key linking to regulatory.approval. Business justification: Clinical genomics accessions for regulated IVD assays must reference the regulatory approval (510(k), CE-IVD) under which the assay is cleared. gxp_applicable_flag on accession signals GxP context. Re',
    `authorized_orderer_id` BIGINT COMMENT 'National Provider Identifier (NPI) or internal identifier of the ordering physician or clinical provider who requisitioned the test. Used for result reporting, billing, and clinical communication. Classified as confidential.',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Lab accessioning links each incoming specimen to the ordered assay/test product (e.g., WGS panel, array). This drives TAT tracking, billing, and result reporting. assay_panel_code is a denormalized re',
    `collection_event_id` BIGINT COMMENT 'Foreign key linking to sample.collection_event. Business justification: Accession (formal laboratory intake) and collection_event (physical specimen collection) are closely coupled transactional records in the sample lifecycle. An accession record corresponds to a specifi',
    `controlled_document_id` BIGINT COMMENT 'Foreign key linking to quality.controlled_document. Business justification: Accessioning is performed under a controlled SOP (e.g., specimen receipt and accessioning procedure). GxP and CLIA compliance require the accession record to reference the governing controlled documen',
    `deviation_id` BIGINT COMMENT 'Foreign key linking to quality.deviation. Business justification: Accessioning deviations (e.g., specimen received outside protocol temperature window, missing requisition) must be formally documented. GxP-regulated genomics labs require the accession event to refer',
    `header_id` BIGINT COMMENT 'Reference to the originating clinical or research order that triggered specimen collection and submission. Links the accession to the order management domain, enabling traceability from test requisition through laboratory intake.',
    `inbound_delivery_id` BIGINT COMMENT 'Foreign key linking to supply.inbound_delivery. Business justification: Specimen accession maps to an inbound delivery record for chain-of-custody, cold-chain compliance, and logistics tracking. Genomics biotech labs receiving specimens from external sites use inbound del',
    `installed_instrument_id` BIGINT COMMENT 'Foreign key linking to customer.installed_instrument. Business justification: In decentralized genomics testing models, accessions are processed on customer-installed instruments (e.g., on-site sequencers). Linking accession to installed_instrument enables instrument utilizatio',
    `irb_submission_id` BIGINT COMMENT 'Foreign key linking to research.irb_submission. Business justification: Accessions for human subjects research must be traceable to the IRB submission authorizing sample collection — a GxP regulatory requirement. accession.irb_protocol_number is a denormalized plain attri',
    `lab_site_id` BIGINT COMMENT 'Reference to the laboratory site that physically received and accessioned the specimen. Supports multi-site operations, routing logic, and site-level compliance reporting under CLIA and CAP.',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Specimens arriving in unacceptable condition (wrong tube, hemolysis, temperature excursion) trigger a nonconformance record. Genomics labs require QMS linkage from the accession receipt event to the f',
    `patient_id` BIGINT COMMENT 'Reference to the de-identified or pseudonymized patient/subject record associated with this specimen. Classified as restricted PHI under HIPAA. Used for clinical traceability while maintaining PHI separation per de-identification protocols.',
    `production_batch_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_batch. Business justification: Accessions (sample receipt events) in clinical genomics labs are assigned to production batches for processing. Linking accession to production_batch enables TAT tracking from receipt to batch complet',
    `project_id` BIGINT COMMENT 'Foreign key linking to research.project. Business justification: Accessioned samples are collected under R&D projects. Linking accessions to projects enables project-level cohort analysis, R&D spend allocation to sample processing, IRB compliance reporting by proje',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the biological sample master record in the Sample Management domain. Establishes the chain-of-custody link between the accession intake event and the canonical sample identity record.',
    `service_agreement_id` BIGINT COMMENT 'Foreign key linking to customer.service_agreement. Business justification: Accessions are governed by customer service agreements that define TAT targets, QC thresholds, and billing terms. SLA compliance reporting and invoice generation for accessioned samples require knowin',
    `study_id` BIGINT COMMENT 'Foreign key linking to research.study. Business justification: Accessions are received in the context of specific studies. Study-level accession tracking is needed for enrollment monitoring, sample accountability reports, and TAT reporting by study. accession alr',
    `subject_id` BIGINT COMMENT 'Foreign key linking to sample.subject. Business justification: accession records the formal intake of a specimen into the laboratory. The specimen originates from a subject (the de-identified/pseudonymized biological source individual). accession has patient_id (',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: In IVD/clinical genomics, sample accessions collected under regulated clinical trials or IVD studies must reference the governing regulatory submission (IND, IDE, PMA). accession.regulatory_submission',
    `test_catalog_id` BIGINT COMMENT 'Foreign key linking to clinical.test_catalog. Business justification: An accession is created for a specific orderable test. Linking accession to test_catalog normalizes the assay_panel_code denormalization, enables TAT SLA enforcement per test type, drives specimen req',
    `accession_number` STRING COMMENT 'LIMS-generated, externally-visible unique identifier assigned to the specimen at the point of intake into LabVantage. Serves as the primary chain-of-custody reference number communicated to ordering clinicians, research teams, and downstream bioinformatics pipelines. Format: ACC-{YYYY}-{8-digit sequence}.. Valid values are `^ACC-[0-9]{4}-[0-9]{8}$`',
    `accession_status` STRING COMMENT 'Current workflow lifecycle state of the accession record within LabVantage. Drives downstream routing: received = physically in lab but not yet reviewed; in_review = condition assessment underway; accepted = cleared for processing; rejected = specimen rejected and not processed; on_hold = pending additional information or consent; cancelled = order cancelled prior to processing.. Valid values are `received|in_review|accepted|rejected|on_hold|cancelled`',
    `accessioning_timestamp` TIMESTAMP COMMENT 'Date and time the specimen was formally registered and accessioned into the LIMS by the receiving technician. May differ from receipt_timestamp if there is a delay between physical receipt and system registration. Used for TAT (Turnaround Time) calculations.',
    `arrival_condition` STRING COMMENT 'Assessment of the physical condition of the specimen upon arrival at the laboratory. acceptable = meets pre-analytical quality criteria; compromised = degraded but may still be processable with notation; rejected = fails minimum quality criteria and cannot be processed. Triggers rejection workflows and recollection requests when set to rejected.. Valid values are `acceptable|compromised|rejected`',
    `collection_date` DATE COMMENT 'Calendar date on which the biological specimen was collected from the patient or subject. Critical for pre-analytical stability assessments, TAT calculations, and clinical result interpretation. Distinct from receipt_timestamp.',
    `collection_site` STRING COMMENT 'Name or identifier of the clinical facility, hospital, clinic, or research site where the specimen was collected from the patient. Supports multi-site clinical trial tracking, referring provider analytics, and logistics routing.',
    `collection_time` TIMESTAMP COMMENT 'Precise date and time the specimen was collected from the patient or subject, including timezone. Used for time-sensitive pre-analytical stability calculations (e.g., RNA degradation, cell viability) and clinical result contextualization.',
    `collector_name` STRING COMMENT 'Name of the phlebotomist, nurse, or clinician who collected the specimen from the patient. Required for chain-of-custody documentation and pre-analytical error investigation. Classified as confidential business data.',
    `condition_notes` STRING COMMENT 'Free-text description of observed pre-analytical issues or anomalies noted at specimen receipt (e.g., hemolysis, lipemia, insufficient volume, broken container, temperature excursion, clotted sample). Supports root cause analysis and pre-analytical QC reporting.',
    `consent_status` STRING COMMENT 'Status of the patient or subjects informed consent for specimen use in research or clinical testing. consented = valid consent obtained; declined = subject declined consent; pending = consent process initiated but not completed; withdrawn = previously consented subject has withdrawn consent; not_required = clinical specimen exempt from research consent requirements.. Valid values are `consented|declined|pending|withdrawn|not_required`',
    `container_type` STRING COMMENT 'Type of container or tube in which the specimen was collected and transported (e.g., EDTA tube, SST tube, PAXgene RNA tube, cryovial, FFPE block, dry swab). Determines extraction protocol eligibility and pre-analytical QC criteria. [ENUM-REF-CANDIDATE: edta_tube|sst_tube|paxgene_rna|paxgene_dna|cryovial|ffpe_block|dry_swab|streck_tube|citrate_tube — promote to reference product]',
    `courier_name` STRING COMMENT 'Name of the courier or logistics provider that transported the specimen to the laboratory (e.g., FedEx, World Courier, BioMatik, internal courier). Used for vendor performance tracking and temperature excursion investigations.',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this accession record was first created in the source LIMS system. Used for data lineage, audit trail, and GxP 21 CFR Part 11 compliance.',
    `external_requisition_number` STRING COMMENT 'Test requisition number assigned by the ordering facilitys own system (e.g., hospital LIS, EHR order number). Enables bidirectional reconciliation between the external ordering system and the internal LIMS accession record.',
    `gxp_applicable_flag` BOOLEAN COMMENT 'Indicates whether this accession falls under GxP (Good Practice Regulations) requirements including GMP, GLP, or GCP. True = GxP controls apply, requiring full audit trail, electronic signature compliance per 21 CFR Part 11, and enhanced documentation in MasterControl.',
    `phi_deidentified_flag` BOOLEAN COMMENT 'Indicates whether Protected Health Information (PHI) associated with this accession has been de-identified per HIPAA Safe Harbor or Expert Determination methods. True = PHI has been de-identified and the record may be used in downstream analytics without PHI restrictions; False = PHI is present and full access controls apply.',
    `priority_level` STRING COMMENT 'Processing priority assigned to the accession at intake. STAT (Short Turn-Around Time) specimens require immediate processing; routine specimens follow standard workflow queues; urgent specimens are expedited but below STAT; research specimens follow non-clinical timelines. Drives SLA (Service Level Agreement) enforcement and workflow queue prioritization in LabVantage.. Valid values are `STAT|routine|urgent|research`',
    `receipt_timestamp` TIMESTAMP COMMENT 'Date and time the specimen was physically received at the laboratory, marking the transition from external courier custody to laboratory custody. This is the principal business event timestamp for the accession transaction. Recorded in ISO 8601 format with timezone offset.',
    `recollection_requested_flag` BOOLEAN COMMENT 'Indicates whether a recollection request has been issued to the ordering provider or collection site due to specimen rejection or insufficient quality. True = recollection has been requested; False = no recollection required.',
    `regulatory_submission_flag` BOOLEAN COMMENT 'Indicates whether this accession is associated with a regulatory submission (e.g., FDA IND/NDA clinical trial specimen, CE-IVD validation study, EMA submission). True = specimen is part of a regulated submission context requiring enhanced documentation and audit trail.',
    `rejection_reason_code` STRING COMMENT 'Standardized code indicating the primary reason a specimen was rejected at accessioning. Populated only when arrival_condition = rejected. Used for pre-analytical QC trending, rejection rate KPI reporting, and recollection request generation. [ENUM-REF-CANDIDATE: insufficient_volume|hemolysis|lipemia|clotted|wrong_tube|unlabeled|temperature_excursion|expired_container|broken_container|mislabeled — promote to reference product]',
    `source_system_record_code` STRING COMMENT 'Native record identifier from the LabVantage LIMS source system for this accession. Used for data lineage traceability between the Databricks Silver Layer and the operational system of record, supporting reconciliation and re-ingestion workflows.',
    `specimen_type` STRING COMMENT 'Standardized classification of the biological specimen material submitted for analysis (e.g., whole blood, FFPE tissue, saliva, buccal swab, plasma, serum, urine, bone marrow, CSF). Drives QC thresholds, extraction protocols, and assay eligibility rules. [ENUM-REF-CANDIDATE: whole_blood|ffpe_tissue|saliva|buccal_swab|plasma|serum|urine|bone_marrow|csf|fresh_frozen_tissue — promote to reference product]',
    `storage_location_code` STRING COMMENT 'Laboratory storage location code (freezer, rack, box, position) where the specimen was placed upon acceptance. Supports physical specimen retrieval, inventory management, and chain-of-custody continuity within the LIMS.',
    `tat_target_hours` STRING COMMENT 'Target Turnaround Time (TAT) in hours from specimen receipt to result delivery, as defined by the SLA (Service Level Agreement) for the assigned priority level and assay type. Used for TAT compliance monitoring and SLA breach alerting.',
    `temperature_at_receipt_c` DECIMAL(18,2) COMMENT 'Measured temperature of the specimen or shipping container at the time of receipt, expressed in degrees Celsius. Used to assess cold-chain compliance and flag potential temperature excursions that may affect specimen integrity and downstream assay validity.',
    `transport_temperature_code` STRING COMMENT 'Required transport temperature condition under which the specimen was shipped to the laboratory. Used to verify compliance with specimen stability requirements and to flag potential temperature excursions during transit.. Valid values are `ambient|refrigerated|frozen|dry_ice|liquid_nitrogen`',
    `tube_label_code` STRING COMMENT 'Barcode or label identifier physically affixed to the specimen container at the time of collection or receipt. Used for physical specimen tracking, label verification at accessioning, and reconciliation against the LIMS accession number.',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this accession record was most recently modified in the source LIMS system. Supports change detection in the Silver Layer ETL pipeline and GxP audit trail requirements.',
    `use_classification` STRING COMMENT 'Intended use classification of the specimen at the time of accessioning. clinical = IVD (In Vitro Diagnostic) or LDT (Laboratory Developed Test) clinical testing; research = RUO (Research Use Only) investigation; QC = Quality Control specimen for assay performance monitoring; validation = analytical validation or clinical validation study specimen.. Valid values are `clinical|research|QC|validation`',
    `volume_received_ml` DECIMAL(18,2) COMMENT 'Measured volume of the specimen received at the laboratory, expressed in millilitres. Used to assess adequacy for requested assays, trigger insufficient volume rejection flags, and support aliquoting planning. Represents the principal quantitative measurement of the accession transaction.',
    `volume_unit` STRING COMMENT 'Unit of measure for the volume_received_ml field. Typically mL for liquid specimens; mg or g for solid tissue specimens. Allows the schema to accommodate non-liquid specimen types without type conversion.. Valid values are `mL|uL|mg|g`',
    CONSTRAINT pk_accession PRIMARY KEY(`accession_id`)
) COMMENT 'Transactional record capturing the formal intake and registration of a specimen into the laboratory information management system (LabVantage). Records accession number (LIMS-generated), receipt date/time, receiving lab site, courier/shipment reference, condition on arrival (acceptable, compromised, rejected), accessioning technician, priority level (STAT, routine), and linkage to the originating clinical order (FK to order domain). Represents the chain-of-custody entry point — the moment a specimen transitions from external custody to laboratory custody.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`biobank_location` (
    `biobank_location_id` BIGINT COMMENT 'Unique surrogate identifier for a physical storage location within the biorepository hierarchy. Primary key for this master resource entity.',
    `change_control_id` BIGINT COMMENT 'Foreign key linking to quality.change_control. Business justification: Change controls often affect storage locations (e.g., equipment upgrades, temperature setpoint changes). Labs link change controls to affected locations for regulatory compliance and audit trails.',
    `lab_site_id` BIGINT COMMENT 'Foreign key linking to sample.lab_site. Business justification: biobank_location (freezers, racks, shelves in the biorepository) is physically located within a lab_site. biobank_location has facility_site_code (STRING) and room_identifier (STRING) that partially c',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Biobank location failures (equipment malfunction, temperature excursion beyond recovery, contamination event) trigger nonconformance records affecting all stored specimens. Direct linkage from biobank',
    `parent_location_biobank_location_id` BIGINT COMMENT 'Self-referencing identifier pointing to the immediate parent location in the biorepository hierarchy (e.g., a boxs parent is a rack, a racks parent is a shelf). Enables recursive hierarchy traversal for chain-of-custody and retrieval workflows.',
    `site_id` BIGINT COMMENT 'Foreign key linking to manufacturing.manufacturing_site. Business justification: Biobank locations are physically within manufacturing sites in genomics biotech (e.g., -80C freezers in GMP facilities). Linking biobank_location to manufacturing_site enables site-level inventory man',
    `validation_study_id` BIGINT COMMENT 'Foreign key linking to quality.validation_study. Business justification: Biobank storage equipment (ULT freezers, cryogenic tanks) must undergo IQ/OQ/PQ validation studies per GMP/ISO 20387. The biobank_location must reference its governing validation study for equipment q',
    `access_restriction_level` STRING COMMENT 'Physical and logical access control classification for this storage location. Governs who may retrieve specimens from this location. restricted and above require role-based authorization in LabVantage LIMS and physical access badge control. Relevant for PHI-linked specimens and BSL-classified materials.. Valid values are `unrestricted|restricted|highly_restricted|biosafety_level_2|biosafety_level_3`',
    `backup_power_protected` BOOLEAN COMMENT 'Indicates whether this storage unit is connected to an uninterruptible power supply (UPS) or emergency generator backup. Critical for specimen integrity risk assessment and business continuity planning for irreplaceable biobank specimens.',
    `barcode` STRING COMMENT 'Machine-readable barcode or 2D matrix code (e.g., DataMatrix, QR) affixed to the physical storage unit or position label. Scanned during specimen accessioning, retrieval, and chain-of-custody verification in LabVantage LIMS.',
    `commissioning_date` DATE COMMENT 'Date on which this storage location was formally commissioned and made available for specimen storage following successful IQ/OQ/PQ qualification. Marks the start of the locations operational lifecycle.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this biobank location record was first created in the system of record (LabVantage LIMS or enterprise data platform). Supports audit trail requirements under GxP, ISO 13485, and 21 CFR Part 11.',
    `decommissioning_date` DATE COMMENT 'Date on which this storage location was permanently decommissioned and removed from active service. Null for locations still in service. Required for equipment lifecycle tracking and regulatory audit trails.',
    `equipment_manufacturer` STRING COMMENT 'Name of the manufacturer of the physical storage equipment (e.g., Thermo Fisher Scientific, Panasonic, Chart Industries). Required for vendor qualification records and regulatory equipment documentation.',
    `equipment_model` STRING COMMENT 'Manufacturer model designation of the physical storage equipment at this location (e.g., Thermo Scientific TSX Series -80°C Freezer). Used for equipment qualification documentation, spare parts management, and maintenance scheduling.',
    `equipment_serial_number` STRING COMMENT 'Manufacturer-assigned serial number of the physical storage equipment. Required for equipment qualification (IQ/OQ/PQ) documentation, warranty tracking, and regulatory audit trails per ISO 13485 and GxP requirements.',
    `hierarchy_level` STRING COMMENT 'Level of this location within the biorepository physical hierarchy: facility → room → freezer → shelf → rack → box → position (well/slot). Enables hierarchical chain-of-custody traversal and capacity roll-up reporting. [ENUM-REF-CANDIDATE: facility|room|freezer|shelf|rack|box|position — 7 candidates stripped; promote to reference product]',
    `is_cryogenic` BOOLEAN COMMENT 'Indicates whether this storage location uses cryogenic conditions (liquid nitrogen vapor or immersion, or mechanical ultra-low temperature ≤ -130°C). Drives safety protocol assignment, PPE requirements, and cryogenic handling SOP routing.',
    `is_gmp_controlled` BOOLEAN COMMENT 'Indicates whether this storage location is subject to GMP regulations (e.g., for clinical trial specimens, IVD reagent intermediates, or GMP-grade biological materials). GMP-controlled locations require enhanced documentation, change control, and audit trail requirements.',
    `is_phi_segregated` BOOLEAN COMMENT 'Indicates whether specimens stored at this location are physically segregated due to PHI linkage, requiring enhanced access controls and HIPAA-compliant chain-of-custody documentation. Supports de-identification workflow management.',
    `last_calibration_date` DATE COMMENT 'Date of the most recent temperature calibration or verification performed on this storage unit. Required for GxP compliance and ISO 15189 accreditation. Tracked in MasterControl and SAP QM.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this biobank location record. Required for change control audit trails under FDA 21 CFR Part 11, ISO 13485, and GxP data integrity requirements.',
    `lims_location_code` STRING COMMENT 'Native location identifier assigned by LabVantage LIMS for this storage position. Used for system-of-record cross-referencing, data lineage tracing, and integration reconciliation between the Silver Layer and the operational LIMS.',
    `location_code` STRING COMMENT 'Externally-known, human-readable unique code assigned to this storage location within the biorepository management system (LabVantage LIMS). Used for labeling, chain-of-custody documentation, and specimen retrieval workflows. Example: FRZ-A01-SH3-RK2-BX05.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `location_name` STRING COMMENT 'Descriptive human-readable name for the storage location, used in operational reports and LIMS displays. Example: Freezer A1 – Shelf 3 – Rack 2 – Box 05.',
    `monitoring_sensor_code` STRING COMMENT 'Identifier of the continuous temperature/humidity monitoring sensor assigned to this storage location. Links to the environmental monitoring system (EMS) for real-time excursion alerting and 21 CFR Part 11-compliant audit trails.',
    `next_calibration_due_date` DATE COMMENT 'Scheduled date for the next temperature calibration or verification of this storage unit. Drives preventive maintenance work orders in SAP S/4HANA PM and compliance alerts in MasterControl.',
    `notes` STRING COMMENT 'Free-text field for operational notes, special handling instructions, or non-conformance observations associated with this storage location (e.g., Door seal replaced 2024-03-15, Reserved for clinical trial XYZ specimens only).',
    `occupied_positions` STRING COMMENT 'Current number of specimen positions occupied at this storage location as tracked by LabVantage LIMS. Enables real-time utilization monitoring and triggers capacity alerts when approaching full occupancy.',
    `operational_status` STRING COMMENT 'Current operational state of this biobank storage location. active = available for specimen storage; maintenance = temporarily unavailable due to servicing; quarantine = specimens held pending investigation; decommissioned = permanently retired from service.. Valid values are `active|inactive|maintenance|decommissioned|quarantine`',
    `position_column` STRING COMMENT 'Numeric column designator for a specific well or slot position within a box or rack (e.g., 1, 12). Applicable at the position/well hierarchy level. Combined with position_row to form the full position address.. Valid values are `^[0-9]{1,3}$`',
    `position_row` STRING COMMENT 'Alphanumeric row designator for a specific well or slot position within a box or rack (e.g., A, B, H). Applicable at the position/well hierarchy level. Combined with position_column to form the full position address.. Valid values are `^[A-Z]{1,3}$`',
    `qualification_expiry_date` DATE COMMENT 'Date on which the current GxP equipment qualification (IQ/OQ/PQ) expires and requalification is required. Drives preventive maintenance scheduling and regulatory compliance alerts in MasterControl.',
    `qualification_status` STRING COMMENT 'GxP qualification status of the storage equipment: qualified = Installation Qualification (IQ), Operational Qualification (OQ), and Performance Qualification (PQ) completed and approved; requalification_required = qualification expired or triggered by maintenance event. Mandatory for GMP/GLP-regulated specimen storage.. Valid values are `qualified|pending_qualification|requalification_required|not_qualified`',
    `responsible_custodian` STRING COMMENT 'Name or employee identifier of the designated biorepository custodian or laboratory manager responsible for this storage location. Accountable for specimen integrity, access authorization, and regulatory compliance at this location.',
    `rfid_tag` STRING COMMENT 'RFID tag identifier assigned to this storage unit for automated inventory scanning and real-time location tracking within the biorepository. Supports high-throughput specimen management workflows.',
    `room_identifier` STRING COMMENT 'Identifier of the laboratory or storage room within the facility where this location physically resides. Used for access control, environmental monitoring zone assignment, and GxP area classification.',
    `specimen_type_compatibility` STRING COMMENT 'Comma-delimited list of specimen types approved for storage at this location (e.g., whole_blood,plasma,FFPE,DNA,RNA,cell_line). Enforced during specimen accessioning in LabVantage LIMS to prevent storage condition mismatches. [ENUM-REF-CANDIDATE: whole_blood|plasma|serum|FFPE|DNA|RNA|cell_line|tissue|urine|saliva — promote to reference product]',
    `storage_medium` STRING COMMENT 'Physical medium used for cryogenic or ambient storage at this location. Distinguishes mechanical freezer cooling from liquid nitrogen (LN2) vapor-phase or immersion-phase storage, which affects specimen viability protocols and safety requirements.. Valid values are `mechanical|liquid_nitrogen_vapor|liquid_nitrogen_immersion|ambient|controlled_room_temperature`',
    `storage_unit_type` STRING COMMENT 'Classification of the physical storage unit at this location level (e.g., freezer, refrigerator, liquid nitrogen tank, ambient cabinet). Drives temperature monitoring SOP assignment and equipment maintenance scheduling.. Valid values are `freezer|refrigerator|liquid_nitrogen_tank|ambient_cabinet|incubator|cryogenic_rack`',
    `temperature_max_c` DECIMAL(18,2) COMMENT 'Upper acceptable temperature limit in degrees Celsius for this storage location. Excursions above this threshold trigger alarms and non-conformance events per SOP.',
    `temperature_min_c` DECIMAL(18,2) COMMENT 'Lower acceptable temperature limit in degrees Celsius for this storage location. Excursions below this threshold trigger alarms and non-conformance events per SOP.',
    `temperature_setpoint_c` DECIMAL(18,2) COMMENT 'Nominal target storage temperature in degrees Celsius for this location (e.g., -80.00 for ultra-low freezer, -196.00 for liquid nitrogen, 4.00 for refrigerator, 22.00 for room temperature). Critical for specimen integrity and regulatory compliance.',
    `total_capacity_positions` STRING COMMENT 'Maximum number of specimen positions (wells, slots, or tubes) this storage location can physically accommodate. Used for capacity planning, utilization reporting, and biorepository space management.',
    CONSTRAINT pk_biobank_location PRIMARY KEY(`biobank_location_id`)
) COMMENT 'Master data entity representing a physical storage location within the biorepository hierarchy — freezer, shelf, rack, box, and well/position. Captures location code, storage unit type, temperature setpoint (e.g., -80°C, -196°C LN2, 4°C, RT), facility site, capacity (total positions, occupied positions), and current operational status. Enables precise chain-of-custody tracking and retrieval of specimens and aliquots.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`storage_event` (
    `storage_event_id` BIGINT COMMENT 'Unique surrogate identifier for each storage state change or custody transfer event record in the chain-of-custody audit trail. Primary key of the storage_event product.',
    `aliquot_id` BIGINT COMMENT 'Reference to the specific aliquot (sub-divided portion of a specimen) involved in this storage event. Nullable when the event applies to the primary specimen rather than a derived aliquot. Populated from LabVantage LIMS aliquot tracking.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to instrument.asset. Business justification: Automated sample handling traceability: robotic liquid handlers and automated storage systems execute storage events in genomics labs. Linking storage_event to the instrument asset enables deviation r',
    `container_id` BIGINT COMMENT 'Foreign key linking to sample.container. Business justification: storage_event tracks custody and storage state changes for specimens and aliquots. The physical container is central to storage tracking — storage_event currently carries container_barcode (STRING) an',
    `lot_id` BIGINT COMMENT 'Foreign key linking to reagent.lot. Business justification: GMP biobanking traceability: cryopreservation storage events consume specific reagent lots (e.g., DMSO, glycerol). Regulatory and GMP chain-of-custody requirements mandate recording which cryoprotecta',
    `biobank_location_id` BIGINT COMMENT 'Reference to the storage location (freezer, rack, shelf, box, or position) to which the specimen or aliquot was moved or placed. Null for disposal or external transfer events where no internal destination exists.',
    `deviation_id` BIGINT COMMENT 'Foreign key linking to quality.quality_deviation. Business justification: Storage events (temperature excursions, unauthorized access, location errors) trigger deviations. Labs document which storage event caused each deviation for regulatory compliance and audit trails.',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Storage events with temperature excursions, unauthorized transfers, or chain-of-custody breaks trigger nonconformance records. Genomics biobanks require direct LIMS-to-QMS linkage from the storage eve',
    `primary_storage_biobank_location_id` BIGINT COMMENT 'Reference to the storage location (freezer, rack, shelf, box, or position) from which the specimen or aliquot was retrieved or transferred. Null for initial placement events where no prior location exists.',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the primary biological specimen (parent sample) involved in this storage event. Links to the specimen master record in LabVantage LIMS for full sample metadata and IRB consent context.',
    `acknowledged_timestamp` TIMESTAMP COMMENT 'Date and time at which the electronic acknowledgment or e-signature was applied to this storage event record. Distinct from the event_timestamp (when the physical action occurred). Required for FDA 21 CFR Part 11 audit trail completeness.',
    `chain_of_custody_sequence` STRING COMMENT 'Monotonically increasing integer representing the ordinal position of this storage event within the complete chain-of-custody history for the specimen or aliquot. Enables ordered reconstruction of the full custody timeline for forensic genomics, legal, and regulatory audit purposes.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time at which this storage event record was first created in the system, in ISO 8601 format with timezone offset. Represents the record audit creation time, distinct from the event_timestamp which captures when the physical action occurred.',
    `deviation_flag` BOOLEAN COMMENT 'Indicates whether this storage event involved a deviation from the applicable SOP or standard storage protocol. True triggers a deviation investigation workflow in the quality management system (Veeva Vault or MasterControl) and requires documented justification.',
    `electronic_acknowledgment_flag` BOOLEAN COMMENT 'Indicates whether the storage event has received a valid electronic acknowledgment (e-signature) from the responsible operator or custodian in compliance with FDA 21 CFR Part 11 electronic records requirements. True confirms the event is electronically signed and locked.',
    `event_number` STRING COMMENT 'Human-readable, externally referenceable identifier for this storage event, formatted as SE-{YYYY}-{YYYYMMDD}-{sequence}. Used in audit reports, chain-of-custody documentation, and regulatory submissions to uniquely reference a specific custody transfer or placement event.. Valid values are `^SE-[0-9]{4}-[0-9]{8}-[0-9]{6}$`',
    `event_status` STRING COMMENT 'Current lifecycle state of the storage event record. Indicates whether the event has been completed, is pending electronic acknowledgment, was cancelled, encountered a failure condition, or is under supervisory review for compliance purposes.. Valid values are `pending|completed|cancelled|failed|under_review`',
    `event_timestamp` TIMESTAMP COMMENT 'The precise real-world date and time at which the storage state change or custody transfer physically occurred, recorded in ISO 8601 format with timezone offset. This is the principal business event time, distinct from the record audit timestamps. Critical for chain-of-custody sequencing and GxP compliance.',
    `event_type` STRING COMMENT 'Categorical discriminator identifying the nature of the storage state change. Drives chain-of-custody logic and audit trail classification. [ENUM-REF-CANDIDATE: initial_placement|relocation|retrieval|return|inter_section_transfer|external_transfer|disposal|quarantine_placement — promote to reference product]',
    `external_site_name` STRING COMMENT 'Name of the external facility, partner laboratory, or clinical site to which the specimen or aliquot was transferred during an inter-site or external transfer event. Populated only for event_type = external_transfer. Supports chain-of-custody documentation for multi-site genomics studies.',
    `external_transfer_tracking_number` STRING COMMENT 'Shipping or courier tracking number associated with an external specimen transfer event. Enables end-to-end shipment traceability for specimens transferred to external sites, partner labs, or clinical collaborators. Populated only for event_type = external_transfer.',
    `freeze_thaw_cycle_count` STRING COMMENT 'Cumulative number of freeze-thaw cycles the specimen or aliquot has undergone up to and including this storage event. Excessive freeze-thaw cycles degrade nucleic acid and protein integrity; this count is critical for sample quality assessment in genomic and clinical workflows.',
    `is_immutable` BOOLEAN COMMENT 'Indicates whether this storage event record has been locked and made immutable following electronic acknowledgment and audit finalization. Immutable records cannot be modified or deleted, satisfying FDA 21 CFR Part 11 and GxP requirements for tamper-evident audit trails.',
    `lims_event_reference` STRING COMMENT 'The native event or transaction identifier assigned by LabVantage LIMS for this storage event. Enables bidirectional traceability between the Databricks Silver Layer data product and the operational LIMS system of record for reconciliation and audit purposes.',
    `phi_deidentified_flag` BOOLEAN COMMENT 'Indicates whether the specimen or aliquot involved in this storage event has been de-identified in accordance with HIPAA Safe Harbor or Expert Determination methods. True means PHI has been removed or anonymized; False means the specimen retains linkage to identifiable patient data.',
    `quarantine_flag` BOOLEAN COMMENT 'Indicates whether the specimen or aliquot was placed into or removed from quarantine status as part of this storage event. Quarantined samples are restricted from use in assays or downstream workflows pending investigation or quality review.',
    `quarantine_reason` STRING COMMENT 'Standardized reason for placing the specimen or aliquot into quarantine. Populated only when quarantine_flag is True. Drives investigation workflows and determines the path to quarantine release or disposal.. Valid values are `temperature_excursion|contamination_suspected|label_discrepancy|consent_issue|qc_failure|pending_investigation`',
    `reason_code` STRING COMMENT 'Standardized reason code explaining the business justification for the storage event. Used for operational reporting, compliance audits, and workflow analytics. [ENUM-REF-CANDIDATE: routine_storage|retrieval_for_assay|transfer_to_external_site|quarantine|inter_section_transfer|disposal_scheduled|emergency_retrieval — promote to reference product]',
    `reason_description` STRING COMMENT 'Free-text narrative providing additional context or justification for the storage event beyond the standardized reason code. Captures operator notes, special circumstances, or deviations from standard operating procedures (SOPs) that require documentation.',
    `required_temp_max_c` DECIMAL(18,2) COMMENT 'The maximum acceptable storage temperature in degrees Celsius for the specimen or aliquot type involved in this event, as defined by the applicable SOP or specimen handling protocol. Used in conjunction with required_temp_min_c to define the acceptable temperature window.',
    `required_temp_min_c` DECIMAL(18,2) COMMENT 'The minimum acceptable storage temperature in degrees Celsius for the specimen or aliquot type involved in this event, as defined by the applicable SOP or specimen handling protocol. Used to evaluate whether a temperature excursion occurred.',
    `sop_reference` STRING COMMENT 'Document identifier of the Standard Operating Procedure (SOP) governing the storage event type performed. Links to the controlled document in MasterControl or Veeva Vault for audit trail completeness and regulatory inspection readiness.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this storage event was originated or ingested into the Databricks Silver Layer. Supports data lineage tracking and reconciliation between the lakehouse and upstream operational systems.. Valid values are `LabVantage|SAP|Manual|API|MES`',
    `specimen_volume_ul` DECIMAL(18,2) COMMENT 'Volume of the specimen or aliquot in microliters (µL) at the time of this storage event. Captured to track volume consumption across retrieval events and to flag low-volume specimens that may be insufficient for planned assays.',
    `storage_condition_code` STRING COMMENT 'Standardized code representing the required storage condition category for the specimen or aliquot at the destination location. Drives storage unit assignment logic and temperature monitoring alert thresholds in the LIMS and facility management systems.. Valid values are `ambient|refrigerated|frozen_minus20|frozen_minus80|liquid_nitrogen|ultra_low`',
    `temperature_at_event_c` DECIMAL(18,2) COMMENT 'Recorded ambient or storage unit temperature in degrees Celsius at the time of the storage event. Captured from connected monitoring systems or manually entered by the operator. Used to assess sample integrity and document temperature excursion conditions.',
    `temperature_excursion_flag` BOOLEAN COMMENT 'Indicates whether a temperature excursion (deviation from the required storage temperature range) was detected or reported in association with this storage event. True signals a potential sample integrity risk requiring investigation and documentation per GxP and CLIA requirements.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time at which this storage event record was most recently modified, in ISO 8601 format with timezone offset. Tracks the last update for audit trail completeness and data lineage purposes. Immutable records will not have an updated_timestamp after locking.',
    CONSTRAINT pk_storage_event PRIMARY KEY(`storage_event_id`)
) COMMENT 'Transactional record of every storage state change and custody transfer for a specimen or aliquot — initial placement, relocation, retrieval, return, and inter-section transfers. Captures event type, source location, destination location, event timestamp, operator ID, custodian identity, reason code (routine storage, retrieval for assay, transfer to external site, quarantine), temperature excursion flag, and electronic acknowledgment. Provides the full chain-of-custody audit trail required for GxP, CLIA, and forensic genomics compliance. Serves as the immutable custody log for all in-facility specimen movements.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`sample_consent_record` (
    `sample_consent_record_id` BIGINT COMMENT 'Unique surrogate identifier for the informed consent record within the Genomics Biotech data platform. Primary key for this entity. Role: MASTER_AGREEMENT — this entity represents a binding ethical and regulatory agreement governing specimen use.',
    `change_control_id` BIGINT COMMENT 'Foreign key linking to quality.change_control. Business justification: Consent form version changes (new consent form version, updated permitted uses) require formal change controls under 21 CFR Part 50 and GDPR. The consent record must reference the change control gover',
    `cohort_id` BIGINT COMMENT 'Foreign key linking to sample.cohort. Business justification: Consent records in genomics research are typically obtained in the context of a specific cohort or study. sample_consent_record has research_protocol_id (cross-domain) but lacks a direct in-domain lin',
    `controlled_document_id` BIGINT COMMENT 'Unique identifier of the consent form document as managed in Veeva Vault regulatory document management system. Enables traceability to the exact document version presented to the subject.',
    `deviation_id` BIGINT COMMENT 'Foreign key linking to quality.deviation. Business justification: Consent deviations (expired consent used, missing re-consent for new data use, consent obtained outside protocol) are formal regulatory deviations in genomics research. Linking consent records to devi',
    `irb_submission_id` BIGINT COMMENT 'Foreign key linking to research.irb_submission. Business justification: Consent records must reference the IRB submission that authorized the research — a direct regulatory requirement (FDA 21 CFR Part 50, ICH E6 GCP). The IRB submission defines the approved consent form ',
    `research_protocol_id` BIGINT COMMENT 'Identifier of the clinical or research study protocol under which the specimen was collected and consent was obtained. Links to the governing study protocol document in Veeva Vault.',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the biological specimen governed by this consent record. Links the consent agreement to the physical sample in the LabVantage LIMS sample tracking system.',
    `study_id` BIGINT COMMENT 'Foreign key linking to research.study. Business justification: Consent records are study-specific — consent form version, IRB protocol, and permitted uses are defined at the study level. Study-level consent tracking is required for regulatory compliance, data gov',
    `subject_id` BIGINT COMMENT 'Reference to the de-identified research subject or patient from whom consent was obtained. Links to the subject/participant master record in the sample domain.',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: Informed consent documentation is required evidence in regulatory submissions for clinical validation studies, IRB compliance verification, and post-market surveillance plans. Essential for FDA/notifi',
    `assent_obtained` BOOLEAN COMMENT 'Indicates whether assent was obtained from a minor subject in addition to parental/guardian consent. Applicable for pediatric genomics studies. Required for IRB compliance in pediatric research protocols.',
    `biobank_consent` BOOLEAN COMMENT 'Indicates whether the subject has consented to long-term biobanking and storage of their specimen for future unspecified research use. Governs specimen retention policies in LabVantage LIMS.',
    `consent_collection_method` STRING COMMENT 'Method by which informed consent was obtained and documented. paper — wet ink signature; electronic — eConsent platform; verbal_with_waiver — IRB-approved verbal consent with waiver of written documentation; remote_electronic — remote eConsent; delegated — consent delegated to authorized representative.. Valid values are `paper|electronic|verbal_with_waiver|remote_electronic|delegated`',
    `consent_collection_site` STRING COMMENT 'Name or code of the clinical or research site where informed consent was obtained (e.g., hospital, clinic, research center). Supports multi-site study management and site-level compliance reporting.',
    `consent_date` DATE COMMENT 'The calendar date on which the research subject or patient provided signed informed consent. This is the principal business event date for the consent agreement and is required for regulatory compliance timelines.',
    `consent_expiry_date` DATE COMMENT 'The date on which the consent authorization expires and must be renewed or re-consented. Null for open-ended broad consents. Used to trigger re-consent workflows and enforce data use restrictions.',
    `consent_form_version` STRING COMMENT 'Version identifier of the IRB-approved informed consent form presented to and signed by the subject (e.g., v1.0, v2.1). Critical for regulatory audit trails to confirm the subject received the current approved version.. Valid values are `^vd+.d+(.d+)?$`',
    `consent_notes` STRING COMMENT 'Free-text field for documenting special circumstances, subject questions, deviations from standard consent process, or other relevant observations recorded during the consent encounter. Confidential — not for general access.',
    `consent_status` STRING COMMENT 'Current lifecycle state of the consent record. active — consent is valid and in force; withdrawn — subject has revoked consent; expired — consent period has lapsed without renewal; pending — awaiting subject signature or IRB approval; superseded — replaced by a newer consent version; revoked — administratively invalidated.. Valid values are `active|withdrawn|expired|pending|superseded|revoked`',
    `consent_type` STRING COMMENT 'Classification of the consent model applied. broad permits use across multiple future research purposes; specific restricts use to a defined study; tiered allows subject to select permitted uses; re_consent indicates updated consent obtained for changed scope; emergency_waiver denotes IRB-approved waiver; assent applies to minors. [ENUM-REF-CANDIDATE: broad|specific|tiered|re_consent|emergency_waiver|assent — promote to reference product]. Valid values are `broad|specific|tiered|re_consent|emergency_waiver|assent`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this consent record was first created in the system, in ISO 8601 format with timezone offset. Supports audit trail requirements under FDA 21 CFR Part 11 and GxP.',
    `deidentification_status` STRING COMMENT 'Current PHI de-identification status of the specimen and associated data. identified — PHI present; de_identified — HIPAA Safe Harbor or Expert Determination method applied; limited_dataset — HIPAA limited dataset with DUA; pseudonymized — GDPR pseudonymization applied; anonymized — irreversibly anonymized.. Valid values are `identified|de_identified|limited_dataset|pseudonymized|anonymized`',
    `future_contact_consent` BOOLEAN COMMENT 'Indicates whether the subject has consented to being contacted for future research studies or re-consent requests. Governs subject outreach activities in Salesforce CRM.',
    `gdpr_lawful_basis` STRING COMMENT 'The GDPR Article 6/9 lawful basis under which personal and special-category genomic data is processed for subjects in EU/EEA jurisdictions. not_applicable for non-EU subjects. Required for GDPR compliance documentation.. Valid values are `consent|vital_interests|public_task|legitimate_interests|not_applicable`',
    `incidental_findings_consent` BOOLEAN COMMENT 'Indicates whether the subject has consented to disclosure of incidental or secondary genomic findings identified during sequencing or analysis (e.g., ACMG secondary findings). Distinct from primary study results.',
    `interpreter_used` BOOLEAN COMMENT 'Indicates whether a language interpreter was used during the consent process. When true, additional interpreter documentation is required per GCP guidelines.',
    `irb_protocol_number` STRING COMMENT 'The unique protocol number assigned by the Institutional Review Board (IRB) governing the study or research program under which this consent was obtained. Required for regulatory traceability and audit.',
    `language_code` STRING COMMENT 'ISO 639-1 language code of the consent form presented to the subject (e.g., en, es, fr, zh-CN). Ensures the subject received consent documentation in their primary language as required by FDA and ICH guidelines.. Valid values are `^[a-z]{2}(-[A-Z]{2})?$`',
    `legally_authorized_representative` BOOLEAN COMMENT 'Indicates whether consent was obtained from a Legally Authorized Representative (LAR) rather than the subject directly (e.g., for incapacitated adults or minors). Triggers additional documentation requirements.',
    `lims_consent_record_code` STRING COMMENT 'The native consent record identifier assigned by LabVantage LIMS. Enables bidirectional traceability between the Databricks Silver Layer data product and the operational LIMS system of record.',
    `permitted_use_clinical` BOOLEAN COMMENT 'Indicates whether the subject has authorized use of their specimen for clinical diagnostic purposes, including In Vitro Diagnostic (IVD) assay validation and Laboratory Developed Test (LDT) workflows under CLIA/CAP.',
    `permitted_use_commercial` BOOLEAN COMMENT 'Indicates whether the subject has authorized use of their specimen and genomic data for commercial product development, including reagent validation, instrument development, and product commercialization activities.',
    `permitted_use_data_sharing` BOOLEAN COMMENT 'Indicates whether the subject has authorized sharing of their de-identified genomic data with external parties, including public genomic databases (e.g., dbGaP, GEO), research consortia, or partner institutions under the NIH Genomic Data Sharing Policy.',
    `permitted_use_research` BOOLEAN COMMENT 'Indicates whether the subject has authorized use of their specimen and associated genomic data for internal Research and Development (R&D) purposes. Governs bioinformatics pipeline processing and variant analysis workflows.',
    `phi_authorization` BOOLEAN COMMENT 'Indicates whether the subject has provided explicit HIPAA authorization for use and disclosure of their Protected Health Information (PHI) in conjunction with specimen and genomic data processing.',
    `re_consent_due_date` DATE COMMENT 'Target date by which re-consent must be obtained from the subject. Null if re-consent is not required. Used to manage compliance timelines and subject outreach scheduling.',
    `re_consent_required` BOOLEAN COMMENT 'Indicates whether a re-consent is required from the subject due to protocol amendments, expanded data use scope, or consent expiry. Triggers re-consent workflow in LabVantage LIMS and MasterControl.',
    `regulatory_jurisdiction` STRING COMMENT 'Primary regulatory jurisdiction applicable to this consent record, using ISO 3166-1 alpha-3 country codes. Determines which regulatory framework (FDA, EMA, IVDR, etc.) governs consent requirements and data handling obligations. [ENUM-REF-CANDIDATE: USA|EU|GBR|CAN|AUS|JPN|CHN|IND|BRA|OTHER — 10 candidates stripped; promote to reference product]',
    `return_of_results_consent` BOOLEAN COMMENT 'Indicates whether the subject has consented to receive individual genomic research results or incidental findings. Governs clinical reporting workflows and genetic counseling referral processes.',
    `sponsor_name` STRING COMMENT 'Name of the sponsoring organization or institution for the study under which consent was obtained. May be Genomics Biotech itself or an external sponsor for collaborative studies.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this consent record was last modified, in ISO 8601 format with timezone offset. Required for change tracking and audit trail compliance under FDA 21 CFR Part 11.',
    `veeva_document_code` STRING COMMENT 'The document identifier in Veeva Vault for the executed consent form document. Provides a direct link to the regulatory document management system for audit and inspection readiness.',
    `withdrawal_date` DATE COMMENT 'The date on which the subject formally withdrew consent. Null if consent has not been withdrawn. When populated, triggers downstream data quarantine and use-restriction enforcement per GDPR right-to-erasure and HIPAA requirements.',
    `withdrawal_reason` STRING COMMENT 'Categorized reason for consent withdrawal. Required for regulatory reporting and adverse event tracking. Null if consent has not been withdrawn. [ENUM-REF-CANDIDATE: subject_request|adverse_event|protocol_deviation|lost_to_followup|deceased|administrative|other — promote to reference product]',
    CONSTRAINT pk_sample_consent_record PRIMARY KEY(`sample_consent_record_id`)
) COMMENT 'Authoritative record of IRB-approved informed consent obtained from a research subject or patient for specimen collection and use. Captures consent form version, IRB protocol number, consent date, consent type (broad, specific, re-consent), scope of permitted use (research, clinical, commercial, data sharing), withdrawal date if applicable, and PHI handling authorization. Links specimen to the governing ethical and regulatory framework. Supports HIPAA, GDPR, and NIH Genomic Data Sharing Policy compliance.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`subject` (
    `subject_id` BIGINT COMMENT 'Unique surrogate identifier for the biological source individual (research participant, patient, donor, or animal model) within the Genomics Biotech data platform. Primary key for the subject master record. Role: MASTER_PARTY.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Research subjects enrolled through customer accounts (clinical sites, research institutions). Required for multi-site study management, institutional consent tracking, data access control, and site-sp',
    `cohort_id` BIGINT COMMENT 'Foreign key linking the enrollment record to the target cohort.',
    `contact_id` BIGINT COMMENT 'Foreign key linking to customer.contact. Business justification: In genomics biobank and clinical research operations, each enrolled subject has a designated customer contact (e.g., clinical coordinator or PI) responsible for re-consent workflows, return-of-results',
    `irb_submission_id` BIGINT COMMENT 'Reference to the IRB or ethics committee protocol under which this subject was enrolled. Links the subject to the governing research protocol, consent framework, and permissible data use scope. Required for regulatory submissions, audit trails, and NIH Genomic Data Sharing Policy compliance.',
    `lab_site_id` BIGINT COMMENT 'Foreign key linking to sample.lab_site. Business justification: subject has a collection_site_code (STRING) that identifies the site where the subject was enrolled/collected. lab_site is the authoritative master for sites within this domain. Adding lab_site_id FK ',
    `patient_id` BIGINT COMMENT 'Foreign key linking to clinical.patient. Business justification: In precision medicine genomics, a research subject and a clinical patient represent the same individual. This link enables return-of-results workflows, incidental findings reporting obligations, longi',
    `risk_assessment_id` BIGINT COMMENT 'Foreign key linking to quality.risk_assessment. Business justification: Subject-level re-identification risk assessments are a formal regulatory requirement under GDPR Article 35 and genomic data governance frameworks. The plain attribute reidentification_risk_level shoul',
    `study_id` BIGINT COMMENT 'Foreign key linking to research.study. Business justification: Subjects are enrolled in studies — this is the fundamental enrollment relationship in clinical genomics research. Subject-to-study traceability is required for participant management, adverse event re',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: In IVD clinical studies and genomics trials, subjects are enrolled under a specific regulatory submission (IDE, IND). This is distinct from IRB submission — it tracks the device/drug regulatory filing',
    `age_at_enrollment` STRING COMMENT 'Age of the subject in whole years at the time of study enrollment, derived from year_of_birth and enrollment_date at data ingestion. Stored as a pre-computed integer to support cohort age-stratification queries without requiring DOB. Enables pediatric vs. adult cohort segmentation and age-related genomic analyses.',
    `ancestry_group` STRING COMMENT 'Self-reported or genetically inferred ancestry/ethnicity group of the subject, used for population genomics stratification, Minor Allele Frequency (MAF) reference panel selection, and pharmacogenomics analyses. Stored as a controlled vocabulary term aligned with gnomAD and 1000 Genomes Project population labels. [ENUM-REF-CANDIDATE: AFR|AMR|EAS|EUR|MID|SAS|ASH|LAT|OTH — promote to reference product]',
    `biobank_consent` BOOLEAN COMMENT 'Indicates whether the subject has consented to long-term biobanking of residual specimens for future research use beyond the primary study. Governs specimen retention policies, storage duration limits, and permissible secondary use of aliquots in LabVantage LIMS.',
    `biological_sex` STRING COMMENT 'Biological sex of the subject as recorded at enrollment, distinct from gender identity. Used for sex-stratified genomic analyses, reference genome selection (e.g., chrX/chrY copy number), population genomics cohort stratification, and clinical assay interpretation.. Valid values are `male|female|intersex|unknown`',
    `collection_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country where the subjects specimens were collected. Drives GDPR data residency requirements, export control compliance for genomic data, and population genomics geographic stratification.. Valid values are `^[A-Z]{3}$`',
    `consent_version` STRING COMMENT 'The version identifier of the informed consent document that was in effect and signed by the subject at the time of enrollment into this cohort. Required for IRB compliance and consent audit trails.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the subject record was first created in the data platform, in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail requirements under GxP, HIPAA, and GDPR, and enables data lineage tracking in the Databricks Silver Layer.',
    `data_access_tier` STRING COMMENT 'Permissible data access level for genomic data derived from this subject, aligned with NIH Genomic Data Sharing Policy tiers. Open access data is publicly available; registered access requires user registration; controlled access requires dbGaP or equivalent approval; restricted access is limited to named investigators under a data use agreement (DUA).. Valid values are `open|registered|controlled|restricted`',
    `deidentification_method` STRING COMMENT 'The HIPAA-recognized or GDPR-compliant method applied to de-identify or pseudonymize the subject record. HIPAA Safe Harbor removes 18 specified identifiers; Expert Determination uses statistical analysis to certify re-identification risk is very small. Pseudonymization replaces direct identifiers with a code while retaining a linkage key in a separate access-controlled system. Drives data access tier assignment and downstream PHI handling rules.. Valid values are `hipaa_safe_harbor|expert_determination|pseudonymization|anonymization`',
    `deidentification_tier` STRING COMMENT 'Classification of the subject records de-identification level per HIPAA and GDPR frameworks. Fully de-identified records have no re-identification pathway; pseudonymized records retain a coded linkage to PHI managed separately; limited dataset records retain certain geographic and date information under a data use agreement (DUA). Governs permissible downstream data uses and sharing.. Valid values are `fully_deidentified|pseudonymized|limited_dataset`',
    `disease_indication` STRING COMMENT 'Primary disease indication or phenotype associated with the subject, encoded using a standardized ontology term (e.g., ICD-10, OMIM, HPO). Drives cohort assembly for clinical genomics studies, variant interpretation in clinical assay workflows, and regulatory submission stratification. Free-text or ontology code depending on study protocol.',
    `disease_indication_ontology` STRING COMMENT 'Ontology or coding system used to encode the disease_indication field (e.g., ICD-10, OMIM, HPO, SNOMED-CT). Enables interoperability across clinical, research, and regulatory systems and ensures consistent variant interpretation and cohort queries.. Valid values are `ICD-10|OMIM|HPO|SNOMED-CT|MeSH|Other`',
    `family_relationship` STRING COMMENT 'Role of this subject within the family pedigree identified by family_id. Used for trio-based variant calling, de novo mutation detection, and inheritance pattern analysis in WGS/WES (Whole Exome Sequencing) workflows. Null for unrelated subjects.. Valid values are `proband|mother|father|sibling|child|other`',
    `gdpr_applicable` BOOLEAN COMMENT 'Indicates whether GDPR applies to this subjects data, based on the subjects collection country and data processing location. When True, GDPR Article 9 special category data protections apply to genetic data, and data subject rights (access, erasure, portability) must be honored. Drives EU data residency and transfer compliance workflows.',
    `genomic_data_sharing_consent` BOOLEAN COMMENT 'Indicates whether the subject has provided explicit consent for their genomic data to be shared with external repositories (e.g., dbGaP, EGA, UK Biobank). Required for NIH Genomic Data Sharing Policy compliance and international data sharing agreements. When False, data must not be submitted to public or controlled-access repositories.',
    `hipaa_applicable` BOOLEAN COMMENT 'Indicates whether HIPAA Privacy Rule applies to this subjects data, based on whether the subject is a US patient or the data is held by a HIPAA-covered entity or business associate. When True, PHI handling, minimum necessary standard, and de-identification requirements apply.',
    `incidental_findings_consent` BOOLEAN COMMENT 'Indicates whether the subject has consented to receive incidental or secondary genomic findings (e.g., ACMG SF v3.2 actionable secondary findings) identified during WGS/WES analysis. Drives the return-of-results workflow and clinical reporting obligations for pathogenic variants in medically actionable genes.',
    `lims_subject_code` STRING COMMENT 'Native subject identifier assigned by LabVantage LIMS at the time of accessioning. Used for cross-system traceability between the Databricks Silver Layer data product and the operational LIMS workflow. Enables reconciliation and lineage tracking back to the system of record.. Valid values are `^[A-Z0-9-]{4,40}$`',
    `notes` STRING COMMENT 'Free-text field for study coordinator or clinical staff annotations regarding the subject record, such as protocol deviations, special handling instructions, or enrollment exceptions. Must not contain direct PHI. Reviewed during data quality audits and IRB annual reviews.',
    `phi_linkage_available` BOOLEAN COMMENT 'Indicates whether a PHI linkage record exists for this subject in the access-controlled consent and identity management system. When True, the subject_code can be re-linked to direct PHI by authorized personnel only. When False, the record is fully de-identified with no re-linkage pathway. Supports HIPAA Safe Harbor compliance auditing.',
    `primary_assay_type` STRING COMMENT 'The primary genomic assay type intended or performed for this subjects specimens. Drives bioinformatics pipeline selection, QC (Quality Control) metric thresholds, and data product routing. WGS (Whole Genome Sequencing), WES (Whole Exome Sequencing), targeted panel, SNP (Single Nucleotide Polymorphism) array, RNA-seq, and methylation array are the principal assay categories. [ENUM-REF-CANDIDATE: WGS|WES|targeted_panel|SNP_array|RNA_seq|methylation_array|other — 7 candidates stripped; promote to reference product]',
    `recontact_consent` BOOLEAN COMMENT 'Indicates whether the subject has consented to being re-contacted for additional studies, incidental findings disclosure, or updated consent. Relevant for longitudinal genomics studies and return-of-results workflows. When False, no re-contact is permitted without a new consent process.',
    `record_version` STRING COMMENT 'Monotonically incrementing version number for the subject record, incremented on each update. Supports optimistic concurrency control, SCD Type 2 history tracking, and GxP audit trail requirements for regulated genomics data. Version 1 represents the initial record creation.',
    `reference_genome_build` STRING COMMENT 'The reference genome assembly version used as the default for bioinformatics pipeline alignment and variant calling for this subjects specimens (e.g., GRCh38 for human, GRCm39 for mouse). Ensures consistency between sample metadata and downstream BAM/VCF (Variant Call Format) outputs. Critical for multi-cohort studies where genome build consistency is required.. Valid values are `GRCh38|GRCh37|GRCm39|GRCm38|Other`',
    `source_system` STRING COMMENT 'Operational system of record from which this subject record was originated or last updated. Enables data lineage traceability and reconciliation between the Databricks Silver Layer and upstream operational systems (primarily LabVantage LIMS for sample domain records).. Valid values are `LabVantage|Benchling|Salesforce|Manual|Other`',
    `species` STRING COMMENT 'Biological species of the subject. Determines applicable reference genome, annotation pipeline, and regulatory classification (human vs. animal model). Critical for bioinformatics pipeline routing and IRB/IACUC compliance.. Valid values are `Homo sapiens|Mus musculus|Rattus norvegicus|Danio rerio|Other`',
    `subject_code` STRING COMMENT 'Externally-known, de-identified alphanumeric code assigned to the subject at accessioning or enrollment. Used as the operational identifier across LIMS, bioinformatics pipelines, and clinical reports without exposing direct PHI. Equivalent to the participant ID or pseudonym in study documentation.. Valid values are `^[A-Z0-9-]{4,30}$`',
    `subject_date` DATE COMMENT 'The calendar date on which the subject was formally enrolled into the cohort. Required for IRB compliance and cohort timeline reporting.',
    `subject_status` STRING COMMENT 'Current lifecycle status of the subjects enrollment in the cohort. Tracks whether the subject is actively participating, has withdrawn, or is in a pending/suspended state.',
    `subject_type` STRING COMMENT 'Classification of the biological source individual by their role in the study or clinical workflow. Drives consent requirements, regulatory handling, and data access controls. Research participants and patients require IRB/ethics board oversight; animal models require IACUC approval.. Valid values are `research_participant|patient|donor|animal_model|cell_line`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the subject record in the data platform, in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change data capture (CDC), incremental pipeline processing, and GxP audit trail compliance.',
    `use_classification` STRING COMMENT 'Regulatory use classification for data and specimens derived from this subject. RUO (Research Use Only) specimens are not intended for clinical diagnosis; IVD (In Vitro Diagnostic) specimens are used in validated clinical assays; LDT (Laboratory Developed Test) specimens are used in laboratory-developed clinical tests. Drives regulatory handling, labeling, and data access controls.. Valid values are `RUO|IVD|LDT|clinical_research|agricultural|other`',
    `withdrawal_date` DATE COMMENT 'Date on which the subject formally withdrew consent or was removed from the study. Triggers downstream data use restriction workflows per HIPAA and GDPR right-to-erasure requirements. Populated only when subject_status is withdrawn.',
    `withdrawal_reason` STRING COMMENT 'Reason for subject withdrawal from the study or clinical program, recorded when subject_status transitions to withdrawn. Supports regulatory audit trails, protocol deviation reporting, and IRB annual review documentation. Populated only when applicable.',
    `year_of_birth` STRING COMMENT 'Four-digit birth year of the subject. Stored instead of full date of birth (DOB) to comply with HIPAA Safe Harbor de-identification requirements (45 CFR §164.514(b)(2)(i)), which prohibit retention of specific birth dates. Enables age-range calculations and cohort age-stratification for population genomics without re-identification risk.',
    CONSTRAINT pk_subject PRIMARY KEY(`subject_id`)
) COMMENT 'De-identified or pseudonymized master record of the biological source individual (research participant, patient, donor, or animal model) from whom specimens are collected. Stores subject code, species, biological sex, year of birth (not full DOB for de-identification), ethnicity/ancestry group (for population genomics), disease indication, de-identification method applied (HIPAA Safe Harbor or Expert Determination), de-identification tier (fully de-identified, pseudonymized, limited dataset), and re-identification risk level. Does NOT store direct PHI — PHI linkage is managed via consent_record and access-controlled separately per HIPAA Safe Harbor. Supports cohort membership tracking via external study enrollment references.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`collection_event` (
    `collection_event_id` BIGINT COMMENT 'Unique surrogate identifier for the specimen collection event record in the Databricks Silver Layer. Primary key for this transactional entity. Role: TRANSACTION_HEADER.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Collection events occur at customer sites. Essential for site-specific protocol compliance monitoring, collection kit logistics coordination, site performance metrics, and regulatory audit trails. Rea',
    `batch_id` BIGINT COMMENT 'Foreign key linking to supply.batch. Business justification: Collection kit batch traceability is a GMP requirement — knowing which supply batch of collection kit material was used at each collection event enables batch recalls and deviation investigations. col',
    `catalog_id` BIGINT COMMENT 'Foreign key linking to reagent.reagent_catalog. Business justification: Collection events use specific collection kit products (PAXgene, Tempus, saliva kits). Critical for tracking kit performance across collection sites, supplier quality monitoring, and correlating pre-a',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Collection events use specific collection kit products. Currently denormalized as collection_kit_sku. Business need: kit lot traceability for regulatory compliance, collection protocol compliance veri',
    `lot_id` BIGINT COMMENT 'Foreign key linking to reagent.lot. Business justification: GMP/GLP collection kit lot traceability: collection_kit_lot_number is a plain text denormalization. Regulatory requirements (CAP, CLIA, ISO 15189) mandate linking collection events to specific reagent',
    `controlled_document_id` BIGINT COMMENT 'Identifier of the Standard Operating Procedure (SOP) document in MasterControl that governed this collection event. Ensures traceability to the approved procedure version used, supporting GxP compliance and audit readiness.',
    `deviation_id` BIGINT COMMENT 'Foreign key linking to quality.deviation. Business justification: Collection events with protocol deviations (wrong tube, collection outside time window, fasting protocol violated) require formal deviation records. The plain attributes deviation_flag/description/typ',
    `header_id` BIGINT COMMENT 'Foreign key linking to order.header. Business justification: Collection events are initiated by service orders in genomics biotech; linking to order.header enables TAT reporting, billing reconciliation, and order-to-collection traceability. collection_order_num',
    `lab_site_id` BIGINT COMMENT 'Foreign key linking to sample.lab_site. Business justification: collection_event has a collection_site_code column typed as BIGINT — this is semantically a reference to a lab_site rather than a free-text code. lab_site is the authoritative master for laboratory an',
    `material_id` BIGINT COMMENT 'Foreign key linking to supply.material. Business justification: Collection kits are materials with SKUs and lot numbers. Linking enables kit inventory management, automated consumption tracking, lot traceability for specimen provenance, and recall management. Remo',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Collection nonconformances (hemolysis at collection, insufficient volume collected, wrong anatomical site) trigger NCRs distinct from deviations. Genomics labs require direct linkage from collection e',
    `project_id` BIGINT COMMENT 'Reference to the research study, clinical trial, or diagnostic project under which this collection event was performed. Enables cohort-level aggregation and study-specific pre-analytical QC reporting.',
    `research_protocol_id` BIGINT COMMENT 'Reference to the Institutional Review Board (IRB) approved protocol under which this collection event was conducted. Mandatory for research specimens; ensures regulatory traceability of consent and ethical approval.',
    `sample_consent_record_id` BIGINT COMMENT 'Reference to the informed consent record obtained from the subject prior to collection. Links to the IRB consent management entity. Mandatory for research and clinical genomics specimens; supports HIPAA, GDPR, and NIH Genomic Data Sharing Policy compliance.',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the primary biological sample record created as a result of this collection event. Links to the sample master entity in the Sample Management domain for downstream LIMS workflow assignments, aliquoting, and storage tracking.',
    `study_id` BIGINT COMMENT 'Foreign key linking to research.study. Business justification: Collection events occur within studies — study-level collection tracking is required for enrollment monitoring, protocol deviation reporting, and collection timeline analysis. collection_event links t',
    `subject_id` BIGINT COMMENT 'Reference to the human subject, patient, or research participant from whom the specimen was collected. Links to the subject/patient master record. Satisfies TRANSACTION_HEADER PARTY_REFERENCE category. Classified restricted/pii_identifier as it directly identifies a research or clinical participant.',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: In clinical trial genomics, collection events are performed under a regulatory submission (IND, IDE, PMA clinical study). collection_event.irb_protocol_number signals regulated context. Linking to sub',
    `test_order_id` BIGINT COMMENT 'Foreign key linking to clinical.test_order. Business justification: A specimen collection event is directly triggered by a clinical test order. This link enables collection-to-order traceability for TAT calculation, recollection workflows, and regulatory audit trails.',
    `training_record_id` BIGINT COMMENT 'Foreign key linking to quality.training_record. Business justification: Training records document that collectors are qualified to perform collections. Labs link training to collection events for regulatory compliance and audit trails.',
    `anatomical_site` STRING COMMENT 'Standardized anatomical location from which the specimen was collected (e.g., left antecubital vein, right breast core, nasopharynx). Encoded using SNOMED CT or ICD-10 topography codes where applicable. Critical for oncology and clinical genomics interpretation.',
    `collection_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code of the country where the specimen was collected. Required for international regulatory compliance (GDPR, IVDR), cross-border data transfer governance, and geographic cohort stratification.. Valid values are `^[A-Z]{3}$`',
    `collection_date` DATE COMMENT 'Calendar date (yyyy-MM-dd) on which the specimen was collected. Stored separately from collection_timestamp to support date-level partitioning, reporting, and cases where only the date (not exact time) is known or required.',
    `collection_event_number` STRING COMMENT 'Human-readable, externally-known business identifier for the collection event, assigned by LabVantage LIMS at accessioning. Used for chain-of-custody documentation, deviation reports, and cross-system traceability. Satisfies TRANSACTION_HEADER BUSINESS_IDENTIFIER category.. Valid values are `^CE-[0-9]{4}-[0-9]{6}$`',
    `collection_method` STRING COMMENT 'Standardized method used to obtain the biological specimen. Drives pre-analytical QC interpretation and NGS library preparation protocol selection. Values: venipuncture (blood draw), biopsy (tissue), swab (mucosal/surface), saliva_kit (self-collected saliva), liquid_biopsy (cell-free DNA from blood), fine_needle_aspiration (FNA cytology).. Valid values are `venipuncture|biopsy|swab|saliva_kit|liquid_biopsy|fine_needle_aspiration`',
    `collection_notes` STRING COMMENT 'Free-text field for additional collector observations, special circumstances, or contextual notes recorded at the time of collection that do not fit into structured fields. Supports clinical interpretation and deviation investigation.',
    `collection_sop_version` STRING COMMENT 'Version number of the SOP document used at the time of collection (e.g., v1.2, v3.0). Stored alongside the SOP ID to capture the exact approved version in effect, as SOP versions change over time.. Valid values are `^v[0-9]+.[0-9]+$`',
    `collection_temperature_c` DECIMAL(18,2) COMMENT 'Ambient or transport temperature in degrees Celsius at the time of or immediately following specimen collection. Used to assess cold-chain compliance and pre-analytical stability. Critical for cfDNA liquid biopsy and RNA specimens.',
    `collection_timestamp` TIMESTAMP COMMENT 'Date and time (ISO 8601 with timezone offset) at which the physical specimen was collected from the subject or environment. This is the principal real-world event time and is critical for pre-analytical time calculations (e.g., time-to-processing, cold-chain compliance). Satisfies TRANSACTION_HEADER BUSINESS_EVENT_TIMESTAMP category.',
    `collection_tube_count` STRING COMMENT 'Number of collection tubes or containers used during the collection event. Relevant for blood draw events with multiple tube types (EDTA, SST, Streck cfDNA). Supports aliquot planning and chain-of-custody reconciliation.',
    `collection_urgency` STRING COMMENT 'Priority classification of the collection event that governs Turnaround Time (TAT) expectations and workflow prioritization in LabVantage LIMS. stat = immediate priority; urgent = same-day; routine = standard TAT.. Valid values are `routine|urgent|stat`',
    `collection_volume_ml` DECIMAL(18,2) COMMENT 'Volume of specimen collected, expressed in millilitres (mL). Used for pre-analytical QC assessment (e.g., short draw detection), yield estimation, and aliquot planning. Satisfies TRANSACTION_HEADER QUANTITATIVE_RESULT category (non-monetary transaction).',
    `collection_volume_unit` STRING COMMENT 'Unit of measure for the collection volume field. Typically mL for liquid specimens; mg or g for solid tissue specimens; uL for micro-volume collections.. Valid values are `mL|uL|mg|g`',
    `collector_certification_number` STRING COMMENT 'Professional certification or license number of the individual who performed the collection (e.g., phlebotomy certification, nursing license). Required for CLIA and CAP compliance documentation and chain-of-custody integrity.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the collection event record was first created in LabVantage LIMS. Used for audit trail, data lineage, and SLA tracking. Satisfies TRANSACTION_HEADER RECORD_AUDIT_CREATED category.',
    `event_status` STRING COMMENT 'Current lifecycle state of the collection event workflow. scheduled = collection planned but not yet performed; in_progress = collector has initiated; completed = specimen successfully collected and handed off; cancelled = event voided before collection; deviated = completed with documented pre-analytical deviation. Satisfies TRANSACTION_HEADER LIFECYCLE_STATUS category.. Valid values are `scheduled|in_progress|completed|cancelled|deviated`',
    `fasting_status` STRING COMMENT 'Pre-analytical fasting status of the subject at the time of collection. Relevant for metabolomics, lipid panels, and certain genomic assays where fasting state affects analyte stability and downstream data quality interpretation.. Valid values are `fasted|non_fasted|unknown`',
    `hemolysis_index` STRING COMMENT 'Semi-quantitative assessment of hemolysis in the collected blood specimen, graded on a standardized scale (none, 1+ to 4+). Hemolysis is a key pre-analytical variable that degrades DNA/RNA quality and affects NGS library preparation success rates.. Valid values are `none|1+|2+|3+|4+`',
    `lims_accession_number` STRING COMMENT 'Accession number assigned by LabVantage LIMS at the time of specimen receipt and registration. Serves as the primary LIMS-side identifier for chain-of-custody tracking and workflow assignment.',
    `phi_deidentified` BOOLEAN COMMENT 'Indicates whether Protected Health Information (PHI) associated with this collection event has been de-identified per HIPAA Safe Harbor or Expert Determination method. True = de-identified; False = identifiable PHI present. Governs data access controls and downstream sharing permissions.',
    `received_timestamp` TIMESTAMP COMMENT 'Date and time the specimen was received at the processing laboratory. Used to calculate time-in-transit and total pre-analytical time (collection to receipt). Critical for TAT reporting and cold-chain compliance verification.',
    `scheduled_collection_date` DATE COMMENT 'Planned calendar date for the collection event as defined in the study protocol or clinical order. Compared against collection_date to calculate collection compliance and protocol adherence metrics.',
    `specimen_type` STRING COMMENT 'Biological specimen type collected. Determines downstream processing protocols, storage conditions, and applicable NGS assay types (e.g., WGS, WES, liquid biopsy ctDNA). [ENUM-REF-CANDIDATE: whole_blood|plasma|serum|buffy_coat|saliva|tissue_ffpe|tissue_fresh_frozen|buccal_swab|urine|csf|stool|bone_marrow|amniotic_fluid — promote to reference product]',
    `time_to_processing_minutes` STRING COMMENT 'Elapsed time in minutes between specimen collection timestamp and the start of primary processing (e.g., centrifugation, nucleic acid extraction). A critical pre-analytical variable for NGS data quality; exceeding thresholds may trigger QC flags or deviation records.',
    `transport_condition` STRING COMMENT 'Required transport temperature condition for the collected specimen from collection site to processing laboratory. Drives cold-chain logistics and is compared against actual temperature readings for pre-analytical QC.. Valid values are `ambient|refrigerated|frozen|dry_ice`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the collection event record in LabVantage LIMS. Supports audit trail requirements and Silver Layer incremental load detection. Satisfies TRANSACTION_HEADER RECORD_AUDIT_UPDATED category.',
    `use_classification` STRING COMMENT 'Regulatory use classification of the specimen collected. RUO = Research Use Only; IVD = In Vitro Diagnostic; LDT = Laboratory Developed Test; clinical_trial = collected under an approved clinical trial protocol; quality_control = internal QC specimen. Determines applicable regulatory framework (FDA, CLIA, CAP) and data handling requirements.. Valid values are `RUO|IVD|LDT|clinical_trial|quality_control`',
    CONSTRAINT pk_collection_event PRIMARY KEY(`collection_event_id`)
) COMMENT 'Transactional record of the physical specimen collection activity. Captures collection date/time, collection site (anatomical location or environmental site), collection method (venipuncture, biopsy, swab, saliva kit, liquid biopsy), collector ID, collection kit lot number, pre-analytical conditions (fasting status, time from collection to processing), and any collection deviations. Provides the pre-analytical metadata critical for NGS data quality interpretation.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`extraction` (
    `extraction_id` BIGINT COMMENT 'Unique identifier for the nucleic acid extraction record. Primary key.',
    `aliquot_id` BIGINT COMMENT 'Foreign key linking to sample.aliquot. Business justification: In genomics workflows, nucleic acid extractions are frequently performed on aliquots (physical sub-divisions of a specimen) rather than the original specimen directly. extraction already has sample_sp',
    `approval_id` BIGINT COMMENT 'Foreign key linking to regulatory.approval. Business justification: Nucleic acid extraction in GxP/IVD genomics labs must be performed under a validated, regulatory-approved method. The extraction record must reference the approval governing the extraction kit/method ',
    `assay_version_id` BIGINT COMMENT 'Foreign key linking to clinical.assay_version. Business justification: Nucleic acid extraction protocols are specified per assay version in genomics labs. Linking extraction to assay_version enables protocol compliance verification, version-specific yield/purity trending',
    `asset_id` BIGINT COMMENT 'Reference to the automated extraction instrument used (e.g., QIAcube, KingFisher Flex). Null if manual extraction.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to supply.batch. Business justification: GMP extraction processes require traceability of the specific supply batch of extraction kit material used. Enables batch recall impact assessment and deviation investigations. Complements existing ma',
    `change_control_id` BIGINT COMMENT 'Foreign key linking to quality.change_control. Business justification: Change controls may affect extraction methods (e.g., new kits, protocol updates). Labs link change controls to affected extractions for traceability and regulatory compliance.',
    `clinical_specimen_id` BIGINT COMMENT 'Foreign key linking to clinical.clinical_specimen. Business justification: A nucleic acid extraction is performed on a specific clinical specimen. This link enables end-to-end clinical traceability from specimen receipt through extraction to genomic result, required for CLIA',
    `deviation_id` BIGINT COMMENT 'Foreign key linking to quality.quality_deviation. Business justification: Extraction failures (low yield, contamination, protocol deviations) are common quality events. Labs link extractions to deviations for process improvement and regulatory documentation.',
    `experiment_id` BIGINT COMMENT 'Foreign key linking to research.experiment. Business justification: Extractions execute experimental protocols. Linking extraction to experiment enables protocol compliance verification, data lineage for publications, assay validation documentation, and regulatory sub',
    `header_id` BIGINT COMMENT 'Foreign key linking to order.order_header. Business justification: Extractions are performed as part of customer service orders (sequencing, genotyping). Links lab processing steps to commercial transactions for billing, quality tracking, and regulatory documentation',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Extraction uses specific kit products. Currently denormalized as extraction_kit_name. Business need: kit lot traceability for regulatory audits, cost-per-extraction calculation for pricing models, inv',
    `lot_id` BIGINT COMMENT 'Foreign key linking to reagent.lot. Business justification: Extraction uses specific reagent kit lots. Essential for correlating extraction yield/quality with reagent lot performance, investigating out-of-specification results, and maintaining GxP traceability',
    `material_id` BIGINT COMMENT 'Foreign key linking to supply.material. Business justification: Extraction kits are materials with material numbers in ERP/LIMS systems. Linking enables inventory consumption tracking, automated reordering, kit lot traceability for regulatory submissions, and CoA ',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Extraction failures (contamination_flag=true, yield below spec, RIN score failure) trigger nonconformance records. Genomics labs require direct linkage from the extraction record to the NCR for batch ',
    `production_batch_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_batch. Business justification: Extracted nucleic acid is a direct input to manufacturing production batches. GMP batch records must document which extraction was used. Traceability from extraction to production batch is required fo',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to reagent.storage_location. Business justification: Chain-of-custody for extracted nucleic acids: extraction.storage_location is a plain text denormalization of the storage location entity. Linking to reagent.storage_location.storage_location_id enable',
    `study_id` BIGINT COMMENT 'Foreign key linking to research.study. Business justification: Extractions are performed to support specific studies (e.g., genomic DNA extraction for a clinical genomics study). Study-level extraction traceability is required for regulatory submissions, study cl',
    `training_record_id` BIGINT COMMENT 'Foreign key linking to quality.training_record. Business justification: Training records document that operators are qualified to perform extractions. Labs link training to extraction activities for audit trails and regulatory compliance.',
    `validation_study_id` BIGINT COMMENT 'Foreign key linking to quality.validation_study. Business justification: Extraction method validations use real extraction runs to demonstrate performance. Labs track which extractions were part of validation studies for regulatory submissions and method qualification.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to manufacturing.work_order. Business justification: Nucleic acid extraction is a controlled manufacturing operation executed via work orders in GMP/GLP environments. This link supports batch record documentation, process validation, deviation tracking,',
    `a260_a230_ratio` DECIMAL(18,2) COMMENT 'Absorbance ratio at 260nm and 230nm wavelengths, indicating contamination by organic compounds or chaotropic salts. Expected range is 2.0-2.2 for pure nucleic acid.',
    `a260_a280_ratio` DECIMAL(18,2) COMMENT 'Absorbance ratio at 260nm and 280nm wavelengths, indicating nucleic acid purity. Pure DNA typically has ratio ~1.8, pure RNA ~2.0. Lower values indicate protein contamination.',
    `barcode` STRING COMMENT 'Unique barcode identifier assigned to the extracted nucleic acid aliquot for tracking and traceability.. Valid values are `^[A-Z0-9]{8,20}$`',
    `concentration_ng_per_ul` DECIMAL(18,2) COMMENT 'Concentration of extracted nucleic acid measured in nanograms per microliter (ng/µL), typically measured by spectrophotometry or fluorometry.',
    `contamination_flag` BOOLEAN COMMENT 'Boolean flag indicating whether contamination was detected during or after extraction (True = contamination detected, False = no contamination).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this extraction record was first created in the LIMS system, in yyyy-MM-ddTHH:mm:ss.SSSXXX format.',
    `dv200_percentage` DECIMAL(18,2) COMMENT 'Percentage of RNA fragments greater than 200 nucleotides, used as quality metric for degraded RNA samples (e.g., FFPE). Values >30% are typically acceptable for NGS.',
    `elution_volume_ul` DECIMAL(18,2) COMMENT 'Final elution volume of the extracted nucleic acid, measured in microliters (µL).',
    `extraction_date` DATE COMMENT 'Date when the nucleic acid extraction was performed, in yyyy-MM-dd format.',
    `extraction_method` STRING COMMENT 'The nucleic acid extraction methodology applied to the specimen (e.g., column-based, magnetic bead, phenol-chloroform, manual, automated, salting-out).. Valid values are `column_based|magnetic_bead|phenol_chloroform|manual|automated|salting_out`',
    `extraction_timestamp` TIMESTAMP COMMENT 'Precise timestamp when the extraction process was completed, in yyyy-MM-ddTHH:mm:ss.SSSXXX format.',
    `input_mass_mg` DECIMAL(18,2) COMMENT 'Mass of input material used for extraction (applicable for solid tissue specimens), measured in milligrams (mg).',
    `input_material_type` STRING COMMENT 'Type of biological specimen used as input for extraction (e.g., whole blood, plasma, serum, tissue, saliva, buccal swab, urine, cerebrospinal fluid, FFPE, fresh frozen). [ENUM-REF-CANDIDATE: whole_blood|plasma|serum|tissue|saliva|buccal_swab|urine|csf|ffpe|fresh_frozen — 10 candidates stripped; promote to reference product]',
    `input_volume_ul` DECIMAL(18,2) COMMENT 'Volume of input material used for extraction, measured in microliters (µL).',
    `intended_use` STRING COMMENT 'Intended downstream application for the extracted nucleic acid (e.g., NGS library preparation, qPCR, array, ddPCR, storage, research, clinical testing). [ENUM-REF-CANDIDATE: ngs_library_prep|qpcr|array|ddpcr|storage|research|clinical_testing — 7 candidates stripped; promote to reference product]',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this extraction record was last modified in the LIMS system, in yyyy-MM-ddTHH:mm:ss.SSSXXX format.',
    `notes` STRING COMMENT 'Free-text field for operator notes, observations, or deviations from standard protocol during the extraction process.',
    `nucleic_acid_type` STRING COMMENT 'Type of nucleic acid extracted: DNA (deoxyribonucleic acid), RNA (ribonucleic acid), cfDNA (cell-free DNA), gDNA (genomic DNA), total nucleic acid, or mRNA (messenger RNA).. Valid values are `DNA|RNA|cfDNA|gDNA|total_nucleic_acid|mRNA`',
    `protocol_version` STRING COMMENT 'Version identifier of the Standard Operating Procedure (SOP) or protocol used for extraction, ensuring traceability to documented procedures.. Valid values are `^[A-Z0-9._-]{3,20}$`',
    `qc_failure_reason` STRING COMMENT 'Detailed explanation of why the extraction failed QC criteria (e.g., low yield, poor purity ratios, degradation). Null if QC passed.',
    `qc_status` STRING COMMENT 'Quality control determination for the extraction: pass (meets all QC criteria), fail (does not meet QC criteria), pending (QC not yet complete), conditional_pass (marginal quality, proceed with caution).. Valid values are `pass|fail|pending|conditional_pass`',
    `quantification_method` STRING COMMENT 'Method used to quantify the extracted nucleic acid (e.g., NanoDrop spectrophotometry, Qubit fluorometry, Bioanalyzer, TapeStation, qPCR, PicoGreen).. Valid values are `nanodrop|qubit|bioanalyzer|tapestation|qpcr|picogreen`',
    `rin_score` DECIMAL(18,2) COMMENT 'RNA Integrity Number score (1-10 scale) indicating RNA quality and degradation level. Applicable only for RNA extractions. Higher scores indicate better integrity.',
    `run_code` STRING COMMENT 'Identifier for the batch or run in which this extraction was performed, linking multiple extractions processed together.. Valid values are `^[A-Z0-9_-]{6,30}$`',
    `storage_temperature_c` STRING COMMENT 'Storage temperature in degrees Celsius for the extracted nucleic acid (e.g., -20°C for DNA, -80°C for RNA).',
    `total_yield_ng` DECIMAL(18,2) COMMENT 'Total yield of extracted nucleic acid in nanograms (ng), calculated as concentration multiplied by elution volume.',
    CONSTRAINT pk_extraction PRIMARY KEY(`extraction_id`)
) COMMENT 'Records the nucleic acid extraction process applied to a specimen or aliquot — producing DNA, RNA, cfDNA, gDNA, or total nucleic acid. Captures extraction method (column-based, magnetic bead, manual, automated), instrument used, extraction kit lot number, input material type and volume, elution volume, yield (ng/µL), purity ratios (A260/A280, A260/A230), extraction date, operator, and pass/fail QC determination. Critical pre-analytical step linking specimen to library preparation in the NGS workflow.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`qc_measurement` (
    `qc_measurement_id` BIGINT COMMENT 'Unique identifier for the quality control measurement record. Primary key for the qc_measurement data product.',
    `aliquot_id` BIGINT COMMENT 'Foreign key linking to sample.aliquot. Business justification: QC measurements (concentration, RIN score, purity ratios) are routinely performed on aliquots in genomics labs — not just on the parent specimen. qc_measurement already has sample_specimen_id but lack',
    `approval_id` BIGINT COMMENT 'Foreign key linking to regulatory.approval. Business justification: QC measurements in IVD/clinical genomics must be performed under approved methods. The approval governs the cleared QC assays intended use and acceptance criteria. Required for IVD compliance reporti',
    `assay_development_id` BIGINT COMMENT 'Foreign key linking to research.assay_development. Business justification: QC measurements are the primary output of assay development — precision, accuracy, LOD/LOQ data are QC measurements tied to an assay_development record. This link is essential for analytical validatio',
    `assay_version_id` BIGINT COMMENT 'Foreign key linking to clinical.assay_version. Business justification: QC measurements are performed against acceptance criteria defined in a specific assay version. This link enables version-specific QC trending, Westgard rule evaluation per assay version, and supports ',
    `asset_id` BIGINT COMMENT 'Reference to the laboratory instrument used to perform the QC measurement. Links to instrument master data for calibration and maintenance tracking.',
    `deviation_id` BIGINT COMMENT 'Foreign key linking to quality.deviation. Business justification: QC measurements that deviate from protocol (e.g., instrument calibration drift, reagent substitution) require a formal deviation record. Genomics labs link QC measurement events to deviations for root',
    `experiment_id` BIGINT COMMENT 'Foreign key linking to research.experiment. Business justification: QC measurements validate experimental protocols and assay performance. Linking measurements to experiments supports assay development validation, protocol optimization cycles, analytical performance s',
    `extraction_id` BIGINT COMMENT 'Foreign key linking to sample.extraction. Business justification: QC measurements are a primary output of the extraction process — purity ratios (A260/A280, A260/A230), RIN scores, and yield measurements are all performed on extracted nucleic acids. qc_measurement h',
    `instrument_run_id` BIGINT COMMENT 'Identifier for the batch or run in which this measurement was performed. Groups multiple measurements performed together for batch-level QC and traceability.',
    `material_id` BIGINT COMMENT 'Foreign key linking to supply.material. Business justification: QC reagents and assay kits are materials. Linking enables reagent lot traceability, validation of QC results against reagent specifications, automated inventory depletion, and regulatory compliance (2',
    `lot_id` BIGINT COMMENT 'Foreign key linking to reagent.lot. Business justification: QC measurements (Qubit quantification, Bioanalyzer sizing, qPCR validation) use specific reagent/standard lots. Essential for assessing measurement validity, investigating out-of-specification results',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: A qc_measurement with pass_fail_flag=FAIL triggers a nonconformance record (e.g., reagent lot failure, instrument out-of-spec). Direct LIMS-to-QMS linkage from the QC measurement to the NCR is require',
    `oos_investigation_id` BIGINT COMMENT 'Foreign key linking to quality.oos_investigation. Business justification: An out-of-specification QC measurement directly initiates an OOS investigation per 21 CFR Part 211 and ICH Q2. The qc_measurement record must reference the OOS investigation for Phase I/II investigati',
    `original_measurement_qc_measurement_id` BIGINT COMMENT 'Reference to the original QC measurement record if this is a repeat measurement. Enables traceability of repeat testing and comparison of results.',
    `production_batch_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_batch. Business justification: In-process QC measurements on samples (library QC, fragment analysis, quantification) are taken during manufacturing production batches. Linking qc_measurement to production_batch supports batch dispo',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: QC measurements use specific reagent products (Qubit assays, Bioanalyzer chips, TapeStation reagents). Business need: measurement validity verification, reagent lot correlation with QC failures, regul',
    `qc_specification_id` BIGINT COMMENT 'Foreign key linking to reagent.qc_specification. Business justification: QC release testing process: every qc_measurement is evaluated against a defined reagent qc_specification (acceptance criteria, limits, test method). Genomics QC analysts require this link to determine',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the biological sample or aliquot on which this QC measurement was performed. Links to the sample master record in LabVantage LIMS.',
    `specification_id` BIGINT COMMENT 'Foreign key linking to product.specification. Business justification: QC measurements (concentration, RIN, A260/A280) are assessed against product specification thresholds (reference_range_lower/upper). Regulatory traceability requires recording which specification vers',
    `test_method_id` BIGINT COMMENT 'Foreign key linking to quality.test_method. Business justification: Every QC measurement is performed using a specific validated test method (e.g., Qubit fluorometry, Bioanalyzer RIN, PicoGreen). Linking to test_method provides analytical traceability, method version ',
    `test_order_id` BIGINT COMMENT 'Foreign key linking to clinical.test_order. Business justification: Pre-analytical and analytical QC measurements are performed as part of specific test order fulfillment. Linking qc_measurement to test_order enables order-level QC reporting, rejection/repeat workflow',
    `a260_a230_ratio` DECIMAL(18,2) COMMENT 'Ratio of absorbance at 260 nm to 230 nm, used to detect contamination from carbohydrates, salts, or phenol. Expected range is 2.0-2.2 for pure nucleic acids.',
    `a260_a280_ratio` DECIMAL(18,2) COMMENT 'Ratio of absorbance at 260 nm to 280 nm, used to assess nucleic acid purity. Pure DNA typically has a ratio of ~1.8, pure RNA ~2.0. Values outside this range indicate contamination.',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time when the measurement was reviewed and approved by quality assurance personnel. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `calibration_date` DATE COMMENT 'Date when the instrument used for this measurement was last calibrated. Ensures measurement accuracy and compliance with quality standards. Format: yyyy-MM-dd.',
    `concentration_ng_ul` DECIMAL(18,2) COMMENT 'Nucleic acid concentration measured in nanograms per microliter. Commonly used for DNA and RNA quantification via Qubit or NanoDrop.',
    `control_sample_flag` BOOLEAN COMMENT 'Boolean indicator of whether this measurement was performed on a control sample (positive control, negative control, or reference standard) rather than a patient or research specimen. True indicates control.',
    `control_type` STRING COMMENT 'Type of control sample used in the measurement, if applicable. Defines the role of the control in the quality assurance process.. Valid values are `positive_control|negative_control|reference_standard|blank|spike_in|not_applicable`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this QC measurement record was first created in the system. Audit trail for data lineage and compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `din_score` DECIMAL(18,2) COMMENT 'DNA Integrity Number (DIN) score ranging from 1 (highly degraded) to 10 (highly intact). Measured via TapeStation electrophoresis. Assesses genomic DNA fragmentation.',
    `fragment_size_bp` STRING COMMENT 'Average or modal fragment size of nucleic acid measured in base pairs. Determined via electrophoresis (Bioanalyzer, TapeStation, or Fragment Analyzer). Critical for library prep QC.',
    `fragment_size_distribution` STRING COMMENT 'Textual or encoded representation of the fragment size distribution profile. May include peak positions, distribution shape, or reference to an electropherogram file.',
    `lims_record_code` STRING COMMENT 'External identifier for this measurement in the source Laboratory Information Management System (LabVantage LIMS). Enables cross-system traceability and reconciliation.',
    `lod_flag` BOOLEAN COMMENT 'Boolean indicator of whether the measured value is below the Limit of Detection (LOD) for the assay. True indicates below LOD. Critical for clinical and research interpretation.',
    `measured_value` DECIMAL(18,2) COMMENT 'Quantitative result of the QC measurement. The numeric value obtained from the instrument or assay. Precision supports high-resolution measurements.',
    `measurement_notes` STRING COMMENT 'Free-text notes or comments recorded by the operator regarding the measurement. May include observations about sample quality, instrument behavior, or deviations from SOP (Standard Operating Procedure).',
    `measurement_status` STRING COMMENT 'Current lifecycle status of the QC measurement. Tracks the measurement from initiation through completion or failure.. Valid values are `pending|in_progress|completed|failed|cancelled|under_review`',
    `measurement_timestamp` TIMESTAMP COMMENT 'Date and time when the QC measurement was performed. Critical for traceability and TAT (Turnaround Time) tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `modified_timestamp` TIMESTAMP COMMENT 'Date and time when this QC measurement record was last modified. Audit trail for data lineage and compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `pass_fail_flag` BOOLEAN COMMENT 'Boolean indicator of whether the measured value falls within the acceptable reference range. True indicates pass, False indicates fail. Drives pre-analytical QC gating decisions.',
    `reference_range_lower` DECIMAL(18,2) COMMENT 'Lower bound of the acceptable reference range for this measurement type. Used to determine pass/fail status and quality gating decisions.',
    `reference_range_upper` DECIMAL(18,2) COMMENT 'Upper bound of the acceptable reference range for this measurement type. Used to determine pass/fail status and quality gating decisions.',
    `repeat_measurement_flag` BOOLEAN COMMENT 'Boolean indicator of whether this measurement is a repeat or retest of a previous measurement. True indicates repeat. Used for tracking measurement reproducibility and troubleshooting.',
    `rin_score` DECIMAL(18,2) COMMENT 'RNA Integrity Number (RIN) score ranging from 1 (completely degraded) to 10 (fully intact). Measured via Bioanalyzer or TapeStation electrophoresis. Critical for RNA-seq quality.',
    `specimen_type` STRING COMMENT 'Type of biological specimen or nucleic acid material on which the QC measurement was performed. Defines the material being assessed. [ENUM-REF-CANDIDATE: whole_blood|plasma|serum|saliva|tissue|dna|rna|cdna|library|amplicon|other — 11 candidates stripped; promote to reference product]',
    `storage_condition` STRING COMMENT 'Storage temperature or condition of the specimen prior to QC measurement. Impacts nucleic acid stability and quality. Critical for pre-analytical quality assessment.. Valid values are `minus_80c|minus_20c|4c|room_temperature|liquid_nitrogen|not_applicable`',
    `unit_of_measure` STRING COMMENT 'Unit of measurement for the measured value. Standardized units ensure consistent interpretation across laboratories and workflows. [ENUM-REF-CANDIDATE: ng_ul|ng|ug|pg|ng_ml|a260_a280_ratio|rin|din|bp|percent — 10 candidates stripped; promote to reference product]',
    CONSTRAINT pk_qc_measurement PRIMARY KEY(`qc_measurement_id`)
) COMMENT 'Captures quantitative and qualitative QC measurements performed on specimens, aliquots, or extracted nucleic acids at any stage of the sample lifecycle. Records measurement type (Qubit fluorometry, NanoDrop spectrophotometry, Bioanalyzer/TapeStation electrophoresis, DIN score, RIN score, fragment size distribution), instrument ID, reagent lot, measured value, unit, reference range, pass/fail flag, and measurement timestamp. Supports LOD tracking and pre-analytical QC gating decisions.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`container` (
    `container_id` BIGINT COMMENT 'Unique surrogate identifier for each physical container record in the LabVantage LIMS. Primary key for the container master entity.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to supply.batch. Business justification: GMP environments require tracing which supply batch of containers (tubes, plates) was used for specimen storage. lot_number is a denormalized representation of supply.batch. Enables container batch re',
    `biobank_location_id` BIGINT COMMENT 'Foreign key linking to sample.biobank_location. Business justification: Containers (tubes, vials, cryovials) are physically stored within biobank locations (freezers, racks, shelves). container currently references reagent.storage_location (cross-domain) but lacks an in-d',
    `lot_id` BIGINT COMMENT 'Foreign key linking to reagent.lot. Business justification: GMP container/consumable lot traceability: container.lot_number is a plain text denormalization of the reagent lot entity. In GMP environments, specimen containers (tubes, plates) are tracked as reage',
    `material_id` BIGINT COMMENT 'Foreign key linking to supply.material. Business justification: Containers (tubes, plates, vials) are consumable materials with material numbers. Linking enables consumable inventory tracking, automated procurement, cost allocation, and supplier management. Remove',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Container failures (cracked tube, label failure, contamination, wrong container type) trigger nonconformance records. Genomics labs require direct linkage from the container record to the NCR for spec',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the biological sample or aliquot currently held within this container. Links container to the sample domain for chain-of-custody traceability.',
    `storage_location_id` BIGINT COMMENT 'Reference to the physical storage location (freezer, rack, shelf, position) where this container is currently housed. Supports barcode-driven inventory management.',
    `validation_study_id` BIGINT COMMENT 'Foreign key linking to quality.validation_study. Business justification: Container types used for specimen storage must be validated (container compatibility studies, leachables/extractables, freeze-thaw stability). Genomics labs reference the validation study governing ea',
    `accessioned_timestamp` TIMESTAMP COMMENT 'Date and time when the container was first registered and accessioned into the LabVantage LIMS system. Marks the start of the container lifecycle and chain-of-custody record. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `barcode` STRING COMMENT 'Unique machine-readable barcode label affixed to the physical container. Used for barcode-driven sample tracking and automated liquid handling workflows in LabVantage LIMS. Must be globally unique across all container inventory.. Valid values are `^[A-Z0-9-]{4,40}$`',
    `cap_color` STRING COMMENT 'Color of the container cap or closure used for visual specimen type identification per laboratory SOP (e.g., red = serum, purple = EDTA whole blood, yellow = SST). Supports pre-analytical sorting and specimen type verification at accessioning.',
    `chain_of_custody_status` STRING COMMENT 'Current integrity status of the chain-of-custody record for this container. Intact = unbroken custody from collection to current location; Broken = a custody gap or anomaly has been detected; Under Review = custody discrepancy under investigation; Verified = custody independently confirmed.. Valid values are `intact|broken|under_review|verified`',
    `concentration_ng_ul` DECIMAL(18,2) COMMENT 'Measured concentration of the nucleic acid or analyte within the container expressed in nanograms per microliter (ng/µL). Captured at accessioning or post-QC measurement. Used for library preparation input normalization and downstream NGS workflow eligibility.',
    `container_status` STRING COMMENT 'Current lifecycle state of the container. Governs whether the container is available for use, actively holding a specimen, reserved for a workflow, or has been removed from inventory. Drives container inventory management and QC workflows.. Valid values are `empty|in_use|reserved|discarded|quarantined|destroyed`',
    `container_type` STRING COMMENT 'Physical form factor classification of the container. Drives liquid handling automation compatibility, storage configuration, and workflow routing in LabVantage. [ENUM-REF-CANDIDATE: tube|plate|vial|cryovial|microplate_well|strip_tube|cartridge — promote to reference product]',
    `current_volume_ul` DECIMAL(18,2) COMMENT 'Current volume of specimen or reagent held within the container expressed in microliters (µL). Updated by LabVantage LIMS upon each aliquoting, dispensing, or consumption event. Enables remaining volume tracking for sample sufficiency checks.',
    `discarded_timestamp` TIMESTAMP COMMENT 'Date and time when the container was formally discarded or destroyed in LabVantage LIMS. Null if the container has not been discarded. Required for chain-of-custody closure, biohazardous waste disposal documentation, and regulatory audit trails.',
    `disposal_method` STRING COMMENT 'Method used to dispose of the container and its contents upon discard or destruction. Required for biohazardous waste compliance documentation and environmental health and safety (EHS) reporting.. Valid values are `autoclave|incineration|chemical_deactivation|biohazard_waste|return_to_sender|other`',
    `expiry_date` DATE COMMENT 'Manufacturer-specified expiration date for the container (e.g., sterility expiry, additive expiry for collection tubes with anticoagulants or preservatives). After this date the container must not be used for specimen collection or storage per GMP and ISO 13485 requirements.',
    `external_code` STRING COMMENT 'Identifier assigned by an external system, partner laboratory, or originating institution (e.g., hospital LIMS ID, biobank accession number). Enables cross-system reconciliation and chain-of-custody linkage.',
    `freeze_thaw_count` STRING COMMENT 'Number of freeze-thaw cycles the container and its contents have undergone. Tracked to assess specimen integrity degradation risk. Exceeding the maximum allowable freeze-thaw cycles per SOP may trigger QC review or specimen disqualification.',
    `intended_use` STRING COMMENT 'Intended use classification of the container and its contents. Determines applicable regulatory framework: clinical specimens are subject to CLIA/CAP and IVD regulations; research specimens fall under RUO designation; QC specimens support internal quality programs; manufacturing specimens are governed by GMP.. Valid values are `clinical|research|qc|manufacturing|validation|proficiency_testing`',
    `irb_protocol_number` STRING COMMENT 'Identifier of the Institutional Review Board (IRB) approved protocol under which the specimen in this container was collected. Required for research use specimens to ensure informed consent compliance. Links container to the governing research ethics approval.',
    `is_dnase_rnase_free` BOOLEAN COMMENT 'Indicates whether the container is certified DNase- and RNase-free (True), ensuring nucleic acid integrity for genomic and transcriptomic applications. Critical for NGS library preparation, RNA sequencing, and qPCR workflows.',
    `is_low_bind` BOOLEAN COMMENT 'Indicates whether the container has a low-binding surface treatment (True) to minimize nucleic acid or protein adsorption to container walls. Important for low-input NGS library preparation and single-cell genomics workflows.',
    `is_phi_deidentified` BOOLEAN COMMENT 'Indicates whether the container label and associated metadata have been de-identified to remove Protected Health Information (PHI) per HIPAA Safe Harbor or Expert Determination method. True = de-identified; False = identifiable PHI present. Governs data access controls and downstream analytics eligibility.',
    `is_sterile` BOOLEAN COMMENT 'Indicates whether the container was manufactured and certified as sterile (True) or is non-sterile (False). Determines eligibility for clinical specimen collection, cell culture applications, and GMP manufacturing workflows.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent update to the container record in LabVantage LIMS. Used for audit trail maintenance, data synchronization, and change detection in the Databricks Silver layer. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `lims_container_code` STRING COMMENT 'Native container identifier assigned by the LabVantage LIMS source system. Preserved for bidirectional reconciliation between the Databricks Silver layer and the operational LIMS. Distinct from the surrogate container_id.',
    `material` STRING COMMENT 'Primary material composition of the container (e.g., polypropylene, glass, polystyrene). Determines chemical compatibility with specimen types, sterilization method eligibility, and storage temperature range.. Valid values are `polypropylene|polyethylene|glass|polystyrene|polycarbonate|borosilicate_glass`',
    `max_freeze_thaw_cycles` STRING COMMENT 'Maximum number of freeze-thaw cycles permitted for the specimen type held in this container before the sample is considered compromised per laboratory SOP. Drives automated QC alerts in LabVantage when freeze_thaw_count is exceeded.',
    `notes` STRING COMMENT 'Free-text field for laboratory staff to record observations, anomalies, handling instructions, or special conditions associated with the container (e.g., visible hemolysis, lipemia, container damage, special handling requirements). Supports chain-of-custody documentation.',
    `plate_position` STRING COMMENT 'Alphanumeric well position identifier for containers that are wells within a microplate or array plate (e.g., A01, H12, P24). Null for standalone tubes and vials. Enables plate-map tracking and automated liquid handling coordination.. Valid values are `^[A-P][0-9]{1,2}$`',
    `qc_status` STRING COMMENT 'Current Quality Control (QC) assessment status of the container contents. Pending = QC not yet performed; Passed = contents meet acceptance criteria; Failed = contents do not meet acceptance criteria; Waived = QC waived per SOP exception; Not Required = QC not applicable for this container type.. Valid values are `pending|passed|failed|waived|not_required`',
    `received_date` DATE COMMENT 'Date the container lot was received into laboratory inventory from the manufacturer or supplier. Used for FIFO inventory management, shelf-life calculation, and incoming QC inspection records in SAP MM.',
    `ruo_flag` BOOLEAN COMMENT 'Indicates whether the container is designated for Research Use Only (RUO) and is not intended for use in clinical diagnostic procedures. True = RUO; False = clinical or IVD use. Required for FDA regulatory compliance labeling and downstream workflow routing.',
    `specimen_type` STRING COMMENT 'Classification of the biological specimen held in the container (e.g., whole blood, FFPE tissue, saliva, buccal swab, plasma, serum, DNA extract, RNA extract, cell line). Drives pre-analytical handling rules, storage temperature requirements, and assay eligibility. [ENUM-REF-CANDIDATE: whole_blood|plasma|serum|dna_extract|rna_extract|ffpe_tissue|saliva|buccal_swab|cell_line|urine — promote to reference product]',
    `storage_temperature_max_c` DECIMAL(18,2) COMMENT 'Maximum allowable storage temperature for the container and its contents expressed in degrees Celsius. Used to validate storage location assignment and trigger temperature excursion alerts. Typical values: 4°C (refrigerator), 25°C (ambient), -20°C (freezer).',
    `storage_temperature_min_c` DECIMAL(18,2) COMMENT 'Minimum allowable storage temperature for the container and its contents expressed in degrees Celsius. Used to validate storage location assignment and trigger alerts for temperature excursions. Typical values: -196°C (liquid nitrogen), -80°C (ultra-low freezer), -20°C (standard freezer).',
    `tube_format` STRING COMMENT 'Standardized format designation of the container (e.g., 1.5 mL Eppendorf, 96-well plate, 384-well plate). Determines compatibility with automated liquid handling instruments, centrifuge rotors, and storage rack configurations. [ENUM-REF-CANDIDATE: 0.2ml|0.5ml|1.5ml|2.0ml|5.0ml|15ml|50ml|96_well|384_well — promote to reference product]. Valid values are `0.2ml|0.5ml|1.5ml|2.0ml|5.0ml|15ml|50ml|96_well|384_well`',
    `volume_capacity_ul` DECIMAL(18,2) COMMENT 'Maximum volumetric capacity of the container expressed in microliters (µL). Used for liquid handling automation, aliquot volume validation, and storage planning. Typical values range from 0.2 µL (PCR strip tube) to 50,000 µL (50 mL conical).',
    CONSTRAINT pk_container PRIMARY KEY(`container_id`)
) COMMENT 'Master entity representing a physical container (tube, plate, vial, cryovial, microplate well) used to hold a specimen or aliquot. Captures container barcode, container type, manufacturer, lot number, material (polypropylene, glass), volume capacity, current contents reference, and container status (empty, in-use, discarded). Enables barcode-driven sample tracking and container inventory management within LabVantage.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`run_sample` (
    `run_sample_id` BIGINT COMMENT 'Unique surrogate identifier for this specimen-run assignment record. Primary key for the run_sample association.',
    `aliquot_id` BIGINT COMMENT 'Foreign key linking to sample.aliquot. Business justification: run_sample represents the operational assignment of biological material to an instrument run (sequencing, array, etc.). In practice, it is the aliquot — not the original specimen — that is physically ',
    `approval_id` BIGINT COMMENT 'Foreign key linking to regulatory.approval. Business justification: Sequencing runs in clinical/IVD genomics must reference the regulatory approval (e.g., NGS panel 510(k) clearance) under which the run is performed. This is a named compliance requirement for clinical',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Each sequencing run sample is processed using a specific reagent kit or flow cell product (catalog item). NGS run planning, yield reporting, and cost-per-sample calculations require knowing which sequ',
    `deviation_id` BIGINT COMMENT 'Foreign key linking to quality.deviation. Business justification: Run-level deviations (index hopping, lane failure, loading concentration outside spec) require formal deviation records. Genomics sequencing labs link run_sample events to deviations for GxP complianc',
    `experiment_id` BIGINT COMMENT 'Foreign key linking to research.experiment. Business justification: A run_sample is the direct execution of an experiments sequencing step. Linking run_sample to experiment enables experiment-level sequencing metrics aggregation (coverage, Q30, reads generated) and s',
    `extraction_id` BIGINT COMMENT 'Foreign key linking to sample.extraction. Business justification: In genomics sequencing workflows, the material loaded onto an instrument run is typically extracted nucleic acid (DNA/RNA) produced by an extraction process. run_sample should reference the extraction',
    `instrument_run_id` BIGINT COMMENT 'Foreign key linking to the instrument run in which this specimen was sequenced. References the run execution record.',
    `line_id` BIGINT COMMENT 'Foreign key linking to order.line. Business justification: Each sequencing run sample fulfills a specific ordered sequencing service line. Linking run_sample to order.line supports per-line service delivery confirmation, TAT compliance tracking, and revenue r',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: A run_sample with run_qc_status=FAIL (e.g., coverage below spec, high duplicate rate) triggers a nonconformance. Sequencing labs require LIMS-to-QMS linkage from the failed run sample to the NCR for r',
    `oos_investigation_id` BIGINT COMMENT 'Foreign key linking to quality.oos_investigation. Business justification: Run samples with OOS sequencing metrics (e.g., percent_q30 below specification, actual_coverage_depth below target) trigger OOS investigations. Direct linkage supports Phase I/II investigation trackin',
    `production_batch_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_batch. Business justification: Sequencing runs in genomics biotech are manufacturing production events. Linking run_sample to production_batch enables batch-level QC reporting, yield tracking, and GMP batch record completion. Opera',
    `sample_specimen_id` BIGINT COMMENT 'Foreign key linking to the biological specimen that was loaded into this sequencing run. References the core specimen master entity.',
    `specification_id` BIGINT COMMENT 'Foreign key linking to product.specification. Business justification: Run QC pass/fail (percent_q30, actual_coverage_depth, actual_reads_generated) is evaluated against a product specification (q30_score_threshold_percent, coverage_depth_min). Regulatory and GxP complia',
    `study_id` BIGINT COMMENT 'Foreign key linking to research.study. Business justification: Sequencing runs are performed in the context of studies. Study-level run tracking is required for coverage reporting, data delivery to study sponsors, and study closeout documentation in clinical geno',
    `test_order_id` BIGINT COMMENT 'Foreign key linking to clinical.test_order. Business justification: A sequencing run sample record must reference the clinical test order it fulfills for TAT tracking, order completion workflows, and billing. In genomics labs, run_sample is the operational record link',
    `actual_coverage_depth` DECIMAL(18,2) COMMENT 'Actual average sequencing coverage depth achieved for this specimen in this run, calculated from actual_reads_generated and reference genome size. Compared against target_coverage_depth to assess run success.',
    `actual_reads_generated` BIGINT COMMENT 'Total number of sequencing reads (or read pairs for paired-end) generated for this specimen in this run, as determined by demultiplexing. Used to calculate actual coverage and assess run balance. Identified in detection phase as relationship data.',
    `assigned_timestamp` TIMESTAMP COMMENT 'Date and time when this specimen was assigned to this run in the LIMS system. Captures when the multiplexing decision was made.',
    `demultiplexed_timestamp` TIMESTAMP COMMENT 'Date and time when demultiplexing completed for this specimen, producing specimen-specific FASTQ files. Marks when per-specimen data became available.',
    `duplicate_rate` DECIMAL(18,2) COMMENT 'Percentage of reads identified as PCR duplicates for this specimen. High duplicate rates indicate over-amplification during library prep or low library complexity.',
    `fastq_file_path` STRING COMMENT 'File system path or cloud storage URI to the demultiplexed FASTQ files for this specimen from this run. Links sequencing data to downstream bioinformatics pipelines.',
    `index_sequence` STRING COMMENT 'Unique index barcode sequence (or dual-index pair) assigned to this specimen for multiplexed sequencing. Used by demultiplexing software to separate reads by specimen. Format: single index (ACGTACGT) or dual index (ACGTACGT+TGCATGCA). Identified in detection phase as relationship data.',
    `lane_number` STRING COMMENT 'Physical lane number on the flow cell where this specimen was loaded (1-8 for HiSeq/NovaSeq). Critical for demultiplexing and per-lane quality assessment. Identified in detection phase as relationship data.',
    `loading_concentration_nm` DECIMAL(18,2) COMMENT 'Molar concentration (nanomolar, nM) of this specimens library at the time of loading into the sequencing run. Influences cluster density and read balance across multiplexed specimens. Identified in detection phase as relationship data.',
    `mean_insert_size` STRING COMMENT 'Average insert size (distance between paired-end reads) for this specimens library in base pairs. Used to assess library preparation quality and detect size selection issues.',
    `percent_aligned` DECIMAL(18,2) COMMENT 'Percentage of this specimens reads that successfully aligned to the reference genome. Low alignment rates indicate contamination, adapter issues, or sample quality problems.',
    `percent_q30` DECIMAL(18,2) COMMENT 'Percentage of bases with Phred quality score of 30 or higher (≥99.9% accuracy) for this specimens reads in this run. Key quality metric for per-specimen QC assessment. Identified in detection phase as relationship data.',
    `pool_position` STRING COMMENT 'Position or slot number of this specimen within the multiplexed pool loaded into the lane. Used for tracking specimen order during library pooling. Identified in detection phase as relationship data.',
    `qc_reviewed_timestamp` TIMESTAMP COMMENT 'Date and time when QC review was completed and run_qc_status was assigned for this specimen-run pairing.',
    `resequencing_required` BOOLEAN COMMENT 'Boolean flag indicating whether this specimen requires re-sequencing due to insufficient coverage, quality issues, or run failure. Drives downstream workflow decisions.',
    `run_qc_status` STRING COMMENT 'Quality control status for this specimen in this run: pass (meets quality thresholds), fail (requires re-sequencing), warning (marginal quality), pending (QC not yet complete). Drives re-sequencing decisions. Identified in detection phase as relationship data.',
    `target_coverage_depth` STRING COMMENT 'Planned average sequencing coverage depth (e.g., 30X for WGS, 100X for WES) for this specific specimen in this run. May differ from the run-level target if specimens have different coverage requirements. Identified in detection phase as relationship data.',
    CONSTRAINT pk_run_sample PRIMARY KEY(`run_sample_id`)
) COMMENT 'This association product represents the operational assignment of a biological specimen to a specific instrument sequencing run. In genomics operations, multiple specimens are routinely multiplexed into a single sequencing run (8-96+ specimens per run), and individual specimens may be re-sequenced across multiple runs for additional coverage, validation, or QC failure recovery. Each record captures the lane assignment, index sequences for demultiplexing, loading concentration, per-specimen read counts, quality metrics, and QC status for each specimen-run pairing. This is the core operational entity that enables multiplexed sequencing workflows and per-specimen quality tracking across the sequencing lifecycle.. Existence Justification: In genomics sequencing operations, specimens and instrument runs have a genuine many-to-many relationship. Multiple specimens (8-96+) are routinely multiplexed into a single sequencing run to maximize instrument utilization and reduce per-specimen cost. Individual specimens are frequently re-sequenced across multiple runs when initial runs fail QC, when additional coverage is needed, or for validation purposes. The business actively manages these specimen-run assignments as operational entities with specific lane assignments, index sequences, loading concentrations, and per-specimen quality metrics.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`cohort` (
    `cohort_id` BIGINT COMMENT 'Primary key for cohort',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Cohorts in genomics are sponsored and owned by specific customer accounts (pharma sponsors, research institutions). Cohort-level data access control, billing reconciliation, and study reporting all re',
    `controlled_document_id` BIGINT COMMENT 'Foreign key linking to quality.controlled_document. Business justification: Cohort definitions and inclusion/exclusion criteria are governed by controlled documents (e.g., cohort selection SOP, IRB-approved study protocol). GxP and IRB compliance require the cohort record to ',
    `approval_id` BIGINT COMMENT 'Reference to the Institutional Review Board approval record.',
    `irb_submission_id` BIGINT COMMENT 'Foreign key linking to research.irb_submission. Business justification: Cohorts require IRB authorization for human subjects research. The IRB submission governs cohort enrollment criteria, consent requirements, and permitted data uses. Direct traceability from cohort to ',
    `lab_site_id` BIGINT COMMENT 'Foreign key linking to sample.lab_site. Business justification: Cohorts in genomics research are typically managed and enrolled at specific laboratory or clinical sites. cohort has geographic_region (STRING) but no direct FK to the lab_site master. Adding lab_site',
    `parent_cohort_id` BIGINT COMMENT 'Self-referencing FK on cohort (parent_cohort_id)',
    `project_id` BIGINT COMMENT 'Foreign key linking to research.project. Business justification: Cohorts are defined and managed within research projects (e.g., a genomics project defines a patient cohort for variant discovery). Project-level cohort management is standard in genomics research; co',
    `risk_assessment_id` BIGINT COMMENT 'Foreign key linking to quality.risk_assessment. Business justification: Cohort-level risk assessments (re-identification risk, data sharing risk, genetic privacy risk) are a regulatory requirement under GDPR and genomic data governance frameworks. The cohort must referenc',
    `service_offering_id` BIGINT COMMENT 'Foreign key linking to product.service_offering. Business justification: Genomics cohorts are enrolled under a specific commercial service offering (e.g., WGS clinical service, pharmacogenomics program). This link drives enrollment eligibility, SLA management, and revenue ',
    `study_id` BIGINT COMMENT 'Identifier of the study associated with the cohort.',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: Cohorts in clinical genomics are defined within regulatory submissions (IND, IDE, PMA clinical study sections). cohort already links to regulatory.approval (irb_approval_id) but not to the submission ',
    `age_range_max` STRING COMMENT 'Maximum age (in years) of participants in the cohort.',
    `age_range_min` STRING COMMENT 'Minimum age (in years) of participants in the cohort.',
    `cohort_code` STRING COMMENT 'Business identifier code for the cohort used in study documentation.',
    `cohort_description` STRING COMMENT 'Detailed description of the cohort purpose and composition.',
    `cohort_name` STRING COMMENT 'Human readable name of the cohort.',
    `cohort_status` STRING COMMENT 'Current lifecycle status of the cohort.',
    `cohort_type` STRING COMMENT 'Category of cohort based on study design.',
    `consent_required_flag` BOOLEAN COMMENT 'Indicates whether informed consent is required for samples in the cohort.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the cohort record was initially captured.',
    `data_access_level` STRING COMMENT 'Level of access permitted for cohort data.',
    `data_retention_period_days` STRING COMMENT 'Number of days data will be retained before archival or deletion.',
    `deidentification_flag` BOOLEAN COMMENT 'Indicates whether samples are de-identified for privacy.',
    `disease_focus` STRING COMMENT 'Primary disease or condition the cohort targets.',
    `effective_end_date` DATE COMMENT 'Date when the cohort is retired or expires.',
    `effective_start_date` DATE COMMENT 'Date when the cohort becomes active for data collection.',
    `ethnicity_inclusion` STRING COMMENT 'Ethnicity groups included in the cohort.',
    `exclusion_criteria` STRING COMMENT 'Text describing criteria for sample exclusion from the cohort.',
    `gender_inclusion` STRING COMMENT 'Gender categories included in the cohort.',
    `geographic_region` STRING COMMENT 'Geographic region(s) covered by the cohort.',
    `inclusion_criteria` STRING COMMENT 'Text describing criteria for sample inclusion in the cohort.',
    `last_data_update_date` DATE COMMENT 'Date of the most recent data refresh for the cohort.',
    `notes` STRING COMMENT 'Additional free-text notes about the cohort.',
    `phenotype` STRING COMMENT 'Phenotypic characteristic(s) defining the cohort.',
    `privacy_tier` STRING COMMENT 'Privacy classification tier for the cohort data.',
    `sample_count` BIGINT COMMENT 'Number of biological samples assigned to the cohort.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the cohort record.',
    `creation_date` DATE COMMENT 'Date the cohort record was first created.',
    CONSTRAINT pk_cohort PRIMARY KEY(`cohort_id`)
) COMMENT 'Master reference table for cohort. Referenced by cohort_id.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sample`.`lab_site` (
    `lab_site_id` BIGINT COMMENT 'Primary key for lab_site',
    `audit_id` BIGINT COMMENT 'Foreign key linking to quality.audit. Business justification: Lab sites are the primary subject of quality audits (internal GMP audits, regulatory inspections, ISO 17025/20387 assessments). Linking lab_site to its most recent or governing audit record is essenti',
    `change_control_id` BIGINT COMMENT 'Foreign key linking to quality.change_control. Business justification: Lab site changes (facility modifications, new equipment installation, capacity expansions) require formal change controls under GMP. The lab_site record must reference the governing change control for',
    `establishment_registration_id` BIGINT COMMENT 'Foreign key linking to regulatory.establishment_registration. Business justification: Every genomics lab site performing IVD testing must be registered with regulatory authorities (FDA establishment registration, ISO 13485). This is a fundamental regulatory requirement. Lab sites map d',
    `parent_lab_site_id` BIGINT COMMENT 'Self-referencing FK on lab_site (parent_lab_site_id)',
    `performing_laboratory_id` BIGINT COMMENT 'Foreign key linking to clinical.performing_laboratory. Business justification: A sample lab_site and a clinical performing_laboratory often represent the same physical facility with different domain perspectives. This link enables CLIA/CAP accreditation status to be surfaced for',
    `risk_assessment_id` BIGINT COMMENT 'Foreign key linking to quality.risk_assessment. Business justification: Lab sites undergo formal facility risk assessments (biosafety risk, GMP compliance risk, business continuity risk). Genomics labs reference site risk assessments for regulatory submissions, insurance,',
    `site_id` BIGINT COMMENT 'Foreign key linking to manufacturing.manufacturing_site. Business justification: In genomics biotech, CLIA/CAP lab sites are co-located within or organizationally subordinate to GMP manufacturing sites. This link supports site-level GMP/CLIA compliance reporting, regulatory inspec',
    `address_line1` STRING COMMENT 'Primary street address of the laboratory site.',
    `address_line2` STRING COMMENT 'Secondary address information (e.g., suite or building).',
    `capacity_samples` BIGINT COMMENT 'Maximum number of biological samples the site can store simultaneously.',
    `certification_expiry` DATE COMMENT 'Date on which the current certification expires.',
    `certification_type` STRING COMMENT 'Regulatory or quality certification held by the site.',
    `city` STRING COMMENT 'City where the laboratory site is located.',
    `closing_date` DATE COMMENT 'Date the site was decommissioned or ceased operations (nullable).',
    `country` STRING COMMENT 'Three‑letter ISO country code of the site location.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the laboratory site record was first created in the system.',
    `deidentification_flag` BOOLEAN COMMENT 'Indicates whether the site enforces de‑identification of protected health information (PHI) for stored samples.',
    `glp_certified` BOOLEAN COMMENT 'Indicates whether the site is certified under Good Laboratory Practice (GLP).',
    `irb_approval_required` BOOLEAN COMMENT 'True if the site requires Institutional Review Board (IRB) approval for sample handling.',
    `lab_site_status` STRING COMMENT 'Current lifecycle status of the site.',
    `latitude` DOUBLE COMMENT 'Geographic latitude of the site (decimal degrees).',
    `longitude` DOUBLE COMMENT 'Geographic longitude of the site (decimal degrees).',
    `opening_date` DATE COMMENT 'Date the site became operational.',
    `site_type` STRING COMMENT 'Category of the site based on its primary function.',
    `state` STRING COMMENT 'State or province of the site location.',
    `storage_temperature_c` DOUBLE COMMENT 'Standard storage temperature maintained at the site for samples, expressed in degrees Celsius.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the laboratory site record.',
    `zip_code` STRING COMMENT 'Postal or ZIP code for the site address.',
    CONSTRAINT pk_lab_site PRIMARY KEY(`lab_site_id`)
) COMMENT 'Master reference table for lab_site. Referenced by lab_site_id.';

